type LinearPartialFractionTerms = Vec<(BigRational, Polynomial, usize)>;

const MAX_EXP_POLYNOMIAL_BY_PARTS_DEGREE: usize = 8;
const MAX_TRIG_POLYNOMIAL_BY_PARTS_DEGREE: usize = 8;
const MAX_HYPERBOLIC_POLYNOMIAL_BY_PARTS_DEGREE: usize = 8;
const SYMBOLIC_INTEGRATION_DOMAIN_PROOF_DEPTH: usize = 8;
const SYMBOLIC_INTEGRATION_DOMAIN_SCAN_DEPTH: usize = 24;

fn valid_constant_log_base_ln(ctx: &mut Context, base: ExprId) -> Option<Option<ExprId>> {
    valid_constant_log_base_ln_from_rational_value(ctx, base, rational_constant_value(ctx, base))
}

fn real_domain_is_empty_or_nonfinite_for_integration(ctx: &mut Context, expr: ExprId) -> bool {
    real_domain_is_empty_or_nonfinite_over_reals(
        ctx,
        expr,
        SYMBOLIC_INTEGRATION_DOMAIN_PROOF_DEPTH,
        SYMBOLIC_INTEGRATION_DOMAIN_SCAN_DEPTH,
    )
}

fn affine_constant_base_log_antiderivative(
    ctx: &mut Context,
    log_expr: ExprId,
    arg: ExprId,
    base_ln: Option<ExprId>,
    var: &str,
) -> Option<ExprId> {
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    if contains_named_var(ctx, a, var) {
        return None;
    }
    affine_constant_base_log_antiderivative_from_slope(
        ctx,
        log_expr,
        arg,
        base_ln,
        a,
        rational_constant_value(ctx, a),
    )
}

fn compact_single_power_polynomial_arg(ctx: &mut Context, arg: ExprId) -> ExprId {
    let factored = factor(ctx, arg);
    if factored == arg {
        return arg;
    }

    match ctx.get(factored) {
        Expr::Pow(_, exp) if is_integer_power_at_least_two(ctx, *exp) => factored,
        _ => arg,
    }
}

fn is_integer_power_at_least_two(ctx: &Context, expr: ExprId) -> bool {
    matches!(
        ctx.get(expr),
        Expr::Number(n)
            if n.denom().is_one() && *n >= BigRational::from_integer(2.into())
    )
}

fn is_number(ctx: &Context, expr: ExprId, value: i64) -> bool {
    matches!(ctx.get(expr), Expr::Number(n) if *n == BigRational::from_integer(value.into()))
}

fn scale_rational_term(ctx: &mut Context, scale: BigRational, term: ExprId) -> ExprId {
    if let Expr::Neg(inner) = ctx.get(term).clone() {
        return scale_rational_term(ctx, -scale, inner);
    }

    if scale.is_one() {
        term
    } else if scale == BigRational::from_integer((-1).into()) {
        ctx.add(Expr::Neg(term))
    } else {
        let scale = ctx.add(Expr::Number(scale));
        mul2_raw(ctx, scale, term)
    }
}

fn rational_over_expr(ctx: &mut Context, numerator: BigRational, denominator: ExprId) -> ExprId {
    if numerator.is_zero() {
        return ctx.num(0);
    }
    if numerator == BigRational::from_integer((-1).into()) {
        let one = ctx.num(1);
        let reciprocal = ctx.add(Expr::Div(one, denominator));
        return ctx.add(Expr::Neg(reciprocal));
    }
    let numerator_expr = ctx.add(Expr::Number(numerator));
    ctx.add(Expr::Div(numerator_expr, denominator))
}

fn is_negative_half(ctx: &Context, expr: ExprId) -> bool {
    match ctx.get(expr) {
        Expr::Number(n) => *n == BigRational::new((-1).into(), 2.into()),
        Expr::Div(num, den) => is_number(ctx, *num, -1) && is_number(ctx, *den, 2),
        Expr::Neg(inner) => match ctx.get(*inner) {
            Expr::Number(n) => *n == BigRational::new(1.into(), 2.into()),
            Expr::Div(num, den) => is_number(ctx, *num, 1) && is_number(ctx, *den, 2),
            _ => false,
        },
        _ => false,
    }
}

fn is_positive_half(ctx: &Context, expr: ExprId) -> bool {
    match ctx.get(expr) {
        Expr::Number(n) => *n == BigRational::new(1.into(), 2.into()),
        Expr::Div(num, den) => is_number(ctx, *num, 1) && is_number(ctx, *den, 2),
        _ => false,
    }
}

fn sqrt_like_radicand(ctx: &Context, expr: ExprId) -> Option<ExprId> {
    match ctx.get(expr) {
        Expr::Function(fn_id, args)
            if args.len() == 1 && ctx.builtin_of(*fn_id) == Some(BuiltinFn::Sqrt) =>
        {
            Some(args[0])
        }
        Expr::Pow(base, exp) if is_positive_half(ctx, *exp) => Some(*base),
        _ => None,
    }
}

fn signed_sqrt_like_radicand(ctx: &Context, expr: ExprId) -> Option<(ExprId, BigRational)> {
    match ctx.get(expr) {
        Expr::Neg(inner) => {
            let radicand = sqrt_like_radicand(ctx, *inner)?;
            Some((radicand, -BigRational::one()))
        }
        _ => sqrt_like_radicand(ctx, expr).map(|radicand| (radicand, BigRational::one())),
    }
}

fn sqrt_chain_argument_derivative_parts(
    ctx: &Context,
    arg: ExprId,
    var: &str,
) -> Option<(ExprId, BigRational)> {
    if let Some(radicand) = sqrt_like_radicand(ctx, arg) {
        return Some((radicand, BigRational::one()));
    }

    match ctx.get(arg) {
        Expr::Add(left, right) => {
            if !contains_named_var(ctx, *left, var) {
                return signed_sqrt_like_radicand(ctx, *right);
            }
            if !contains_named_var(ctx, *right, var) {
                return signed_sqrt_like_radicand(ctx, *left);
            }
            None
        }
        Expr::Sub(left, right) => {
            if !contains_named_var(ctx, *left, var) {
                let (radicand, sign) = signed_sqrt_like_radicand(ctx, *right)?;
                return Some((radicand, -sign));
            }
            if !contains_named_var(ctx, *right, var) {
                return signed_sqrt_like_radicand(ctx, *left);
            }
            None
        }
        _ => None,
    }
}

fn reciprocal_sqrt_like_radicand(ctx: &Context, expr: ExprId) -> Option<ExprId> {
    match ctx.get(expr) {
        Expr::Pow(base, exp) if is_negative_half(ctx, *exp) => Some(*base),
        _ => None,
    }
}

fn var_power(ctx: &Context, expr: ExprId, var: &str) -> Option<BigRational> {
    match ctx.get(expr) {
        Expr::Variable(sym_id) if ctx.sym_name(*sym_id) == var => Some(BigRational::one()),
        Expr::Pow(base, exp) if is_var(ctx, *base, var) => rational_constant_value(ctx, *exp),
        _ => None,
    }
}

fn scaled_var_power_term(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(BigRational, BigRational)> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut power = None;

    for factor in factors {
        if let Some(factor_power) = var_power(ctx, factor, var) {
            if power.is_some() {
                return None;
            }
            power = Some(factor_power);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    Some((scale, power?))
}

#[derive(Clone)]
struct SqrtLinearDenominator {
    scale: BigRational,
    slope: BigRational,
    offset: BigRational,
}

#[derive(Clone, Copy)]
enum SymbolicSquareShiftArgument {
    DivideByParameter,
    MultiplyByParameter,
}

struct SymbolicSquareShiftDenominator {
    scale: BigRational,
    parameter: ExprId,
    argument: SymbolicSquareShiftArgument,
    argument_scale: BigRational,
}

fn positive_linear_polynomial_coeffs(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(BigRational, BigRational)> {
    let poly = Polynomial::from_expr(ctx, expr, var).ok()?;
    if poly.degree() != 1 {
        return None;
    }

    let offset = poly
        .coeffs
        .first()
        .cloned()
        .unwrap_or_else(BigRational::zero);
    let slope = poly
        .coeffs
        .get(1)
        .cloned()
        .unwrap_or_else(BigRational::zero);
    (slope.is_positive() && offset.is_positive()).then_some((slope, offset))
}

fn non_integrating_parameter_square(ctx: &Context, expr: ExprId, var: &str) -> Option<ExprId> {
    let Expr::Pow(base, exp) = ctx.get(expr) else {
        return None;
    };
    if rational_constant_value(ctx, *exp) != Some(BigRational::from_integer(2.into())) {
        return None;
    }
    if contains_named_var(ctx, *base, var) {
        return None;
    }
    match ctx.get(*base) {
        Expr::Variable(_) => Some(*base),
        _ => None,
    }
}

fn var_plus_symbolic_parameter_square(ctx: &Context, expr: ExprId, var: &str) -> Option<ExprId> {
    let Expr::Add(left, right) = ctx.get(expr) else {
        return None;
    };
    if is_var(ctx, *left, var) {
        return non_integrating_parameter_square(ctx, *right, var);
    }
    if is_var(ctx, *right, var) {
        return non_integrating_parameter_square(ctx, *left, var);
    }
    None
}

fn numeric_square_scaled_var_plus_symbolic_parameter_square(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(ExprId, BigRational)> {
    let Expr::Add(left, right) = ctx.get(expr) else {
        return None;
    };

    let match_scaled_var = |term: ExprId, square_term: ExprId| {
        let (scale, power) = scaled_var_power_term(ctx, term, var)?;
        if power != BigRational::one() {
            return None;
        }
        let scale_root = exact_rational_sqrt(&scale)?;
        if scale_root.is_zero() {
            return None;
        }
        let parameter = non_integrating_parameter_square(ctx, square_term, var)?;
        Some((parameter, scale_root))
    };

    match_scaled_var(*left, *right).or_else(|| match_scaled_var(*right, *left))
}

fn symbolic_parameter_square_times_var(ctx: &Context, expr: ExprId, var: &str) -> Option<ExprId> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut saw_var = false;
    let mut parameter = None;

    for factor in factors {
        if is_var(ctx, factor, var) {
            if saw_var {
                return None;
            }
            saw_var = true;
        } else if let Some(square_parameter) = non_integrating_parameter_square(ctx, factor, var) {
            if parameter.is_some() {
                return None;
            }
            parameter = Some(square_parameter);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    (saw_var && scale.is_one()).then_some(parameter?)
}

fn symbolic_parameter_square_times_var_plus_one(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let Expr::Add(left, right) = ctx.get(expr) else {
        return None;
    };
    if is_number(ctx, *left, 1) {
        return symbolic_parameter_square_times_var(ctx, *right, var);
    }
    if is_number(ctx, *right, 1) {
        return symbolic_parameter_square_times_var(ctx, *left, var);
    }
    None
}

fn symbolic_square_shift_argument_parts(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(ExprId, SymbolicSquareShiftArgument, BigRational)> {
    if let Some(parameter) = var_plus_symbolic_parameter_square(ctx, expr, var) {
        return Some((
            parameter,
            SymbolicSquareShiftArgument::DivideByParameter,
            BigRational::one(),
        ));
    }
    if let Some((parameter, argument_scale)) =
        numeric_square_scaled_var_plus_symbolic_parameter_square(ctx, expr, var)
    {
        return Some((
            parameter,
            SymbolicSquareShiftArgument::DivideByParameter,
            argument_scale,
        ));
    }
    symbolic_parameter_square_times_var_plus_one(ctx, expr, var).map(|parameter| {
        (
            parameter,
            SymbolicSquareShiftArgument::MultiplyByParameter,
            BigRational::one(),
        )
    })
}

fn sqrt_var_times_symbolic_square_shift_denominator(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<SymbolicSquareShiftDenominator> {
    let factors = mul_leaves(ctx, den);
    let mut scale = BigRational::one();
    let mut saw_sqrt_var = false;
    let mut square_shift = None;

    for factor in factors {
        if sqrt_like_radicand(ctx, factor).is_some_and(|radicand| is_var(ctx, radicand, var)) {
            if saw_sqrt_var {
                return None;
            }
            saw_sqrt_var = true;
        } else if let Some(parts) = symbolic_square_shift_argument_parts(ctx, factor, var) {
            if square_shift.is_some() {
                return None;
            }
            square_shift = Some(parts);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    let (parameter, argument, argument_scale) = square_shift?;
    saw_sqrt_var.then_some(SymbolicSquareShiftDenominator {
        scale,
        parameter,
        argument,
        argument_scale,
    })
}

fn reciprocal_sqrt_var_over_symbolic_square_shift_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<SymbolicSquareShiftDenominator> {
    let (parameter, argument, argument_scale) =
        symbolic_square_shift_argument_parts(ctx, den, var)?;
    let factors = mul_leaves(ctx, num);
    let mut scale = BigRational::one();
    let mut saw_reciprocal_sqrt_var = false;

    for factor in factors {
        if reciprocal_sqrt_like_radicand(ctx, factor)
            .is_some_and(|radicand| is_var(ctx, radicand, var))
        {
            if saw_reciprocal_sqrt_var {
                return None;
            }
            saw_reciprocal_sqrt_var = true;
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    saw_reciprocal_sqrt_var.then_some(SymbolicSquareShiftDenominator {
        scale,
        parameter,
        argument,
        argument_scale,
    })
}

fn arctan_sqrt_var_symbolic_square_shift_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<SymbolicSquareShiftDenominator> {
    if let Some(parts) = sqrt_var_times_symbolic_square_shift_denominator(ctx, den, var) {
        let numerator_scale = rational_constant_value(ctx, num)?;
        return Some(SymbolicSquareShiftDenominator {
            scale: numerator_scale / parts.scale,
            parameter: parts.parameter,
            argument: parts.argument,
            argument_scale: parts.argument_scale,
        });
    }

    reciprocal_sqrt_var_over_symbolic_square_shift_parts(ctx, num, den, var)
}

fn sqrt_var_times_positive_linear_denominator(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<SqrtLinearDenominator> {
    let factors = mul_leaves(ctx, den);
    let mut scale = BigRational::one();
    let mut saw_sqrt_var = false;
    let mut linear_coeffs = None;

    for factor in factors {
        if sqrt_like_radicand(ctx, factor).is_some_and(|radicand| is_var(ctx, radicand, var)) {
            if saw_sqrt_var {
                return None;
            }
            saw_sqrt_var = true;
        } else if let Some(coeffs) = positive_linear_polynomial_coeffs(ctx, factor, var) {
            if linear_coeffs.is_some() {
                return None;
            }
            linear_coeffs = Some(coeffs);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    let (slope, offset) = linear_coeffs?;
    saw_sqrt_var.then_some(SqrtLinearDenominator {
        scale,
        slope,
        offset,
    })
}

fn expanded_sqrt_var_times_positive_linear_denominator(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<SqrtLinearDenominator> {
    let (left, right) = match ctx.get(den) {
        Expr::Add(left, right) => (*left, *right),
        _ => return None,
    };
    let (left_scale, left_power) = scaled_var_power_term(ctx, left, var)?;
    let (right_scale, right_power) = scaled_var_power_term(ctx, right, var)?;

    let half = BigRational::new(1.into(), 2.into());
    let three_halves = BigRational::new(3.into(), 2.into());
    let (offset, slope) = if left_power == half && right_power == three_halves {
        (left_scale, right_scale)
    } else if left_power == three_halves && right_power == half {
        (right_scale, left_scale)
    } else {
        return None;
    };

    (slope.is_positive() && offset.is_positive()).then_some(SqrtLinearDenominator {
        scale: BigRational::one(),
        slope,
        offset,
    })
}

fn sqrt_var_times_positive_linear_parts(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<SqrtLinearDenominator> {
    sqrt_var_times_positive_linear_denominator(ctx, den, var)
        .or_else(|| expanded_sqrt_var_times_positive_linear_denominator(ctx, den, var))
}

fn reciprocal_sqrt_var_over_positive_linear_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<SqrtLinearDenominator> {
    let (slope, offset) = positive_linear_polynomial_coeffs(ctx, den, var)?;

    let factors = mul_leaves(ctx, num);
    let mut scale = BigRational::one();
    let mut saw_reciprocal_sqrt_var = false;

    for factor in factors {
        if reciprocal_sqrt_like_radicand(ctx, factor)
            .is_some_and(|radicand| is_var(ctx, radicand, var))
        {
            if saw_reciprocal_sqrt_var {
                return None;
            }
            saw_reciprocal_sqrt_var = true;
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    saw_reciprocal_sqrt_var.then_some(SqrtLinearDenominator {
        scale,
        slope,
        offset,
    })
}

fn arctan_sqrt_var_positive_linear_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<SqrtLinearDenominator> {
    if let Some(parts) = sqrt_var_times_positive_linear_parts(ctx, den, var) {
        if parts.scale.is_zero() {
            return None;
        }
        let numerator_scale = rational_constant_value(ctx, num)?;
        return Some(SqrtLinearDenominator {
            scale: numerator_scale / parts.scale,
            slope: parts.slope,
            offset: parts.offset,
        });
    }

    reciprocal_sqrt_var_over_positive_linear_parts(ctx, num, den, var)
}

struct PositiveSquareShiftDenominator {
    scale: BigRational,
    offset: BigRational,
    offset_root: BigRational,
}

fn positive_square_shift_linear_square_parts(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(BigRational, BigRational)> {
    let Expr::Pow(base, exp) = ctx.get(expr) else {
        return None;
    };
    if rational_constant_value(ctx, *exp) != Some(BigRational::from_integer(2.into())) {
        return None;
    }
    let (slope, offset) = positive_linear_polynomial_coeffs(ctx, *base, var)?;
    if !slope.is_one() || !offset.is_positive() {
        return None;
    }
    let offset_root = exact_rational_sqrt(&offset)?;
    Some((offset, offset_root))
}

fn positive_square_shift_linear_square_denominator_parts(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<PositiveSquareShiftDenominator> {
    let factors = mul_leaves(ctx, den);
    let mut scale = BigRational::one();
    let mut square_offset = None;
    let mut square_offset_root = None;

    for factor in factors {
        if let Some((offset, offset_root)) =
            positive_square_shift_linear_square_parts(ctx, factor, var)
        {
            if square_offset.is_some() {
                return None;
            }
            square_offset = Some(offset);
            square_offset_root = Some(offset_root);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    Some(PositiveSquareShiftDenominator {
        scale,
        offset: square_offset?,
        offset_root: square_offset_root?,
    })
}

fn sqrt_var_times_positive_square_shift_linear_square_denominator_parts(
    ctx: &Context,
    den: ExprId,
    var: &str,
) -> Option<PositiveSquareShiftDenominator> {
    let factors = mul_leaves(ctx, den);
    let mut scale = BigRational::one();
    let mut saw_sqrt_var = false;
    let mut square_offset = None;
    let mut square_offset_root = None;

    for factor in factors {
        if sqrt_like_radicand(ctx, factor).is_some_and(|radicand| is_var(ctx, radicand, var)) {
            if saw_sqrt_var {
                return None;
            }
            saw_sqrt_var = true;
        } else if let Some((offset, offset_root)) =
            positive_square_shift_linear_square_parts(ctx, factor, var)
        {
            if square_offset.is_some() {
                return None;
            }
            square_offset = Some(offset);
            square_offset_root = Some(offset_root);
        } else {
            scale *= rational_constant_value(ctx, factor)?;
        }
    }

    saw_sqrt_var.then_some(PositiveSquareShiftDenominator {
        scale,
        offset: square_offset?,
        offset_root: square_offset_root?,
    })
}

fn reciprocal_sqrt_var_over_positive_square_shift_linear_square_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<PositiveSquareShiftDenominator> {
    let denominator = positive_square_shift_linear_square_denominator_parts(ctx, den, var)?;
    let factors = mul_leaves(ctx, num);
    let mut numerator_scale = BigRational::one();
    let mut saw_reciprocal_sqrt_var = false;

    for factor in factors {
        if reciprocal_sqrt_like_radicand(ctx, factor)
            .is_some_and(|radicand| is_var(ctx, radicand, var))
        {
            if saw_reciprocal_sqrt_var {
                return None;
            }
            saw_reciprocal_sqrt_var = true;
        } else {
            numerator_scale *= rational_constant_value(ctx, factor)?;
        }
    }

    saw_reciprocal_sqrt_var.then_some(PositiveSquareShiftDenominator {
        scale: numerator_scale / denominator.scale,
        offset: denominator.offset,
        offset_root: denominator.offset_root,
    })
}

fn sqrt_var_over_var_times_positive_square_shift_linear_square_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<PositiveSquareShiftDenominator> {
    let numerator_factors = mul_leaves(ctx, num);
    let mut numerator_scale = BigRational::one();
    let mut saw_sqrt_var = false;
    for factor in numerator_factors {
        if sqrt_like_radicand(ctx, factor).is_some_and(|radicand| is_var(ctx, radicand, var)) {
            if saw_sqrt_var {
                return None;
            }
            saw_sqrt_var = true;
        } else {
            numerator_scale *= rational_constant_value(ctx, factor)?;
        }
    }
    if !saw_sqrt_var {
        return None;
    }

    let denominator_factors = mul_leaves(ctx, den);
    let mut denominator_scale = BigRational::one();
    let mut saw_var = false;
    let mut square_offset = None;
    let mut square_offset_root = None;
    for factor in denominator_factors {
        if is_var(ctx, factor, var) {
            if saw_var {
                return None;
            }
            saw_var = true;
        } else if let Some((offset, offset_root)) =
            positive_square_shift_linear_square_parts(ctx, factor, var)
        {
            if square_offset.is_some() {
                return None;
            }
            square_offset = Some(offset);
            square_offset_root = Some(offset_root);
        } else {
            denominator_scale *= rational_constant_value(ctx, factor)?;
        }
    }

    saw_var.then_some(PositiveSquareShiftDenominator {
        scale: numerator_scale / denominator_scale,
        offset: square_offset?,
        offset_root: square_offset_root?,
    })
}

fn arctan_sqrt_var_unit_shift_square_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<PositiveSquareShiftDenominator> {
    if let Some(denominator) =
        sqrt_var_times_positive_square_shift_linear_square_denominator_parts(ctx, den, var)
    {
        if denominator.scale.is_zero() {
            return None;
        }
        let numerator_scale = rational_constant_value(ctx, num)?;
        return Some(PositiveSquareShiftDenominator {
            scale: numerator_scale / denominator.scale,
            offset: denominator.offset,
            offset_root: denominator.offset_root,
        });
    }

    reciprocal_sqrt_var_over_positive_square_shift_linear_square_parts(ctx, num, den, var).or_else(
        || sqrt_var_over_var_times_positive_square_shift_linear_square_parts(ctx, num, den, var),
    )
}

fn arctan_sqrt_var_reciprocal_antiderivative_from_parts(
    ctx: &mut Context,
    scale: BigRational,
    slope: BigRational,
    offset: BigRational,
    var: &str,
) -> Option<ExprId> {
    if scale.is_zero() {
        return None;
    }
    if !slope.is_positive() || !offset.is_positive() {
        return None;
    }

    let product = slope.clone() * offset.clone();
    let product_root = exact_rational_sqrt(&product)?;
    let ratio = slope / offset;
    let ratio_root = exact_rational_sqrt(&ratio)?;

    let var_expr = ctx.var(var);
    let sqrt_var = ctx.call_builtin(BuiltinFn::Sqrt, vec![var_expr]);
    let arctan_arg = scale_factor(ctx, ratio_root, sqrt_var);
    let arctan = ctx.call_builtin(BuiltinFn::Arctan, vec![arctan_arg]);
    Some(scale_factor(
        ctx,
        scale * BigRational::from_integer(2.into()) / product_root,
        arctan,
    ))
}

fn arctan_sqrt_var_reciprocal_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let parts = arctan_sqrt_var_positive_linear_parts(ctx, num, den, var)?;
    arctan_sqrt_var_reciprocal_antiderivative_from_parts(
        ctx,
        parts.scale,
        parts.slope,
        parts.offset,
        var,
    )
}

fn arctan_sqrt_var_symbolic_square_shift_antiderivative_from_parts(
    ctx: &mut Context,
    scale: BigRational,
    parameter: ExprId,
    argument: SymbolicSquareShiftArgument,
    argument_scale: BigRational,
    var: &str,
) -> Option<ExprId> {
    if scale.is_zero() || argument_scale.is_zero() || contains_named_var(ctx, parameter, var) {
        return None;
    }

    let var_expr = ctx.var(var);
    let sqrt_var = ctx.call_builtin(BuiltinFn::Sqrt, vec![var_expr]);
    let scaled_sqrt_var = scale_factor(ctx, argument_scale.clone(), sqrt_var);
    let arctan_arg = match argument {
        SymbolicSquareShiftArgument::DivideByParameter => {
            ctx.add(Expr::Div(scaled_sqrt_var, parameter))
        }
        SymbolicSquareShiftArgument::MultiplyByParameter => {
            mul2_raw(ctx, parameter, scaled_sqrt_var)
        }
    };
    let arctan = ctx.call_builtin(BuiltinFn::Arctan, vec![arctan_arg]);
    let coefficient = scale * BigRational::from_integer(2.into()) / argument_scale;
    if coefficient.is_one() {
        return Some(ctx.add(Expr::Div(arctan, parameter)));
    }
    if coefficient == BigRational::from_integer((-1).into()) {
        let quotient = ctx.add(Expr::Div(arctan, parameter));
        return Some(ctx.add(Expr::Neg(quotient)));
    }
    let coefficient = rational_over_expr(ctx, coefficient, parameter);
    Some(mul2_raw(ctx, coefficient, arctan))
}

fn arctan_sqrt_var_symbolic_square_shift_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let parts = arctan_sqrt_var_symbolic_square_shift_parts(ctx, num, den, var)?;
    arctan_sqrt_var_symbolic_square_shift_antiderivative_from_parts(
        ctx,
        parts.scale,
        parts.parameter,
        parts.argument,
        parts.argument_scale,
        var,
    )
}

fn arctan_sqrt_var_unit_shift_square_antiderivative_from_scale(
    ctx: &mut Context,
    scale: BigRational,
    offset: BigRational,
    offset_root: BigRational,
    var: &str,
) -> Option<ExprId> {
    if scale.is_zero() || !offset.is_positive() || !offset_root.is_positive() {
        return None;
    }

    let var_expr = ctx.var(var);
    let sqrt_var = ctx.call_builtin(BuiltinFn::Sqrt, vec![var_expr]);
    if offset.is_one() && offset_root.is_one() {
        let arctan = ctx.call_builtin(BuiltinFn::Arctan, vec![sqrt_var]);
        let one = ctx.num(1);
        let unit_shift = ctx.add(Expr::Add(var_expr, one));
        let quotient = ctx.add(Expr::Div(sqrt_var, unit_shift));
        let primitive = build_balanced_add(ctx, &[arctan, quotient]);
        return Some(scale_factor(ctx, scale, primitive));
    }

    let arctan_arg = if offset_root.is_one() {
        sqrt_var
    } else if offset_root < BigRational::one() {
        scale_factor(ctx, BigRational::one() / offset_root.clone(), sqrt_var)
    } else {
        let offset_root_expr = ctx.add(Expr::Number(offset_root.clone()));
        ctx.add(Expr::Div(sqrt_var, offset_root_expr))
    };
    let arctan = ctx.call_builtin(BuiltinFn::Arctan, vec![arctan_arg]);
    let offset_expr = ctx.add(Expr::Number(offset.clone()));
    let shifted = ctx.add(Expr::Add(var_expr, offset_expr));
    let quotient_term = if offset.is_one() {
        ctx.add(Expr::Div(sqrt_var, shifted))
    } else if offset < BigRational::one() {
        let scaled_numerator = scale_factor(ctx, scale.clone() / offset.clone(), sqrt_var);
        ctx.add(Expr::Div(scaled_numerator, shifted))
    } else {
        let offset_expr = ctx.add(Expr::Number(offset.clone()));
        let offset_denominator = build_balanced_mul(ctx, &[offset_expr, shifted]);
        let quotient = ctx.add(Expr::Div(sqrt_var, offset_denominator));
        scale_factor(ctx, scale.clone(), quotient)
    };
    let arctan_term = scale_factor(ctx, scale.clone() / (offset.clone() * offset_root), arctan);
    Some(build_balanced_add(ctx, &[arctan_term, quotient_term]))
}

fn arctan_sqrt_var_unit_shift_square_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let parts = arctan_sqrt_var_unit_shift_square_parts(ctx, num, den, var)?;
    arctan_sqrt_var_unit_shift_square_antiderivative_from_scale(
        ctx,
        parts.scale,
        parts.offset,
        parts.offset_root,
        var,
    )
}

fn arctan_sqrt_var_reciprocal_required_positive_radicand(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return None;
    };
    let matches_positive_linear_form =
        arctan_sqrt_var_positive_linear_parts(ctx, *num, *den, var).is_some();
    let matches_unit_shift_square_form =
        arctan_sqrt_var_unit_shift_square_parts(ctx, *num, *den, var).is_some();
    let matches_symbolic_square_shift_form =
        arctan_sqrt_var_symbolic_square_shift_parts(ctx, *num, *den, var).is_some();
    if matches_positive_linear_form
        || matches_unit_shift_square_form
        || matches_symbolic_square_shift_form
    {
        return Some(ctx.var(var));
    }
    None
}

fn arctan_sqrt_var_symbolic_square_shift_required_nonzero_parameter(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return None;
    };
    arctan_sqrt_var_symbolic_square_shift_parts(ctx, *num, *den, var).map(|parts| parts.parameter)
}

struct ArctanSqrtAffineDerivativeParts {
    radicand: ExprId,
    scale: BigRational,
    argument_scale: BigRational,
}

struct ArctanSqrtAffineGapParts {
    argument_scale: BigRational,
    denominator_root: BigRational,
    kernel_scale_factor: BigRational,
}

#[derive(Clone, Copy)]
enum InverseHyperbolicSqrtReciprocalKind {
    Asinh,
    Atanh,
}

struct InverseHyperbolicSqrtReciprocalParts {
    base: Polynomial,
    constant: BigRational,
    scale: BigRational,
    scale_sqrt_factor: Option<BigRational>,
}

fn inverse_hyperbolic_scale_over_constant_root(
    scale_without_root: BigRational,
    constant: &BigRational,
) -> Option<(BigRational, Option<BigRational>)> {
    if let Some(root) = exact_rational_sqrt(constant) {
        return Some((scale_without_root / root, None));
    }

    constant.is_positive().then(|| {
        (
            scale_without_root / constant.clone(),
            Some(constant.clone()),
        )
    })
}

fn scale_rational_sqrt_term(
    ctx: &mut Context,
    scale: BigRational,
    sqrt_factor: BigRational,
    expr: ExprId,
) -> Option<ExprId> {
    let sqrt_expr = positive_rational_sqrt_expr(ctx, &sqrt_factor)?;
    let scaled_sqrt = scale_rational_term(ctx, scale, sqrt_expr);
    Some(mul2_raw(ctx, scaled_sqrt, expr))
}

fn normalize_asinh_reciprocal_display_base(
    base: Polynomial,
    constant: BigRational,
) -> (Polynomial, BigRational) {
    if exact_rational_sqrt(&constant).is_some() {
        return (base, constant);
    }

    let content = base.content();
    if content.is_zero() || !content.is_positive() || content.is_one() {
        return (base, constant);
    }

    let normalized_constant = constant.clone() / content.clone();
    if normalized_constant.is_positive() && exact_rational_sqrt(&normalized_constant).is_some() {
        (base.div_scalar(&content), normalized_constant)
    } else {
        (base, constant)
    }
}

fn normalize_atanh_reciprocal_display_base(
    base: Polynomial,
    constant: BigRational,
) -> (Polynomial, BigRational) {
    let content = base.content();
    if content.is_zero() || !content.is_positive() || content.is_one() {
        return (base, constant);
    }

    let normalized_constant = constant.clone() / content.clone();
    if normalized_constant.is_positive() {
        (base.div_scalar(&content), normalized_constant)
    } else {
        (base, constant)
    }
}

fn affine_polynomial(ctx: &Context, expr: ExprId, var: &str) -> Option<Polynomial> {
    let poly = Polynomial::from_expr(ctx, expr, var).ok()?;
    (poly.degree() == 1).then_some(poly)
}

fn positive_constant_difference(left: &Polynomial, right: &Polynomial) -> Option<BigRational> {
    let diff = left.sub(right);
    if diff.degree() != 0 {
        return None;
    }
    let constant = diff
        .coeffs
        .first()
        .cloned()
        .unwrap_or_else(BigRational::zero);
    constant.is_positive().then_some(constant)
}

fn single_affine_factor(ctx: &Context, factors: &[ExprId], var: &str) -> Option<Polynomial> {
    let [factor] = factors else {
        return None;
    };
    affine_polynomial(ctx, *factor, var)
}

fn atanh_gap_constant_and_alignment(
    base: &Polynomial,
    gap_factor: &Polynomial,
) -> Option<(BigRational, BigRational)> {
    let base_slope = base.coeffs.get(1).cloned()?;
    let gap_slope = gap_factor.coeffs.get(1).cloned()?;
    if base_slope.is_zero() || gap_slope.is_zero() {
        return None;
    }
    let gap_alignment = base_slope / gap_slope;
    if gap_alignment.is_zero() {
        return None;
    }
    let alignment_reciprocal = BigRational::one() / gap_alignment.clone();
    let gap = gap_factor.div_scalar(&alignment_reciprocal);
    let constant = positive_constant_difference(base, &gap)?;
    Some((constant, gap_alignment))
}

fn asinh_normalized_sqrt_reciprocal_parts(
    ctx: &Context,
    sqrt_radicand: ExprId,
    polynomial_factors: &[ExprId],
    num_scale: BigRational,
    den_scale: BigRational,
    var: &str,
) -> Option<InverseHyperbolicSqrtReciprocalParts> {
    if polynomial_factors.len() != 2 || den_scale.is_zero() {
        return None;
    }
    let sqrt_poly = affine_polynomial(ctx, sqrt_radicand, var)?;

    for base_idx in 0..2 {
        let base = affine_polynomial(ctx, polynomial_factors[base_idx], var)?;
        let constant = positive_constant_difference(&sqrt_poly, &base)?;
        let offset = base
            .coeffs
            .first()
            .cloned()
            .unwrap_or_else(BigRational::zero);
        if offset.is_negative() {
            continue;
        }

        let radicand_factor =
            Polynomial::from_expr(ctx, polynomial_factors[1 - base_idx], var).ok()?;
        let radicand_ratio = constant_polynomial_ratio(&sqrt_poly, &radicand_factor)?;
        let slope = base.coeffs.get(1).cloned()?;
        if slope.is_zero() {
            continue;
        }
        let kernel_scale = num_scale.clone() * radicand_ratio / den_scale.clone();
        let scale_without_root = -BigRational::from_integer(2.into()) * kernel_scale / slope;
        let (scale, scale_sqrt_factor) =
            inverse_hyperbolic_scale_over_constant_root(scale_without_root, &constant)?;
        let (base, constant) = normalize_asinh_reciprocal_display_base(base, constant);
        return Some(InverseHyperbolicSqrtReciprocalParts {
            base,
            constant,
            scale,
            scale_sqrt_factor,
        });
    }

    None
}

fn atanh_normalized_sqrt_reciprocal_parts(
    ctx: &Context,
    sqrt_radicand: ExprId,
    polynomial_factors: &[ExprId],
    num_scale: BigRational,
    den_scale: BigRational,
    var: &str,
) -> Option<InverseHyperbolicSqrtReciprocalParts> {
    if polynomial_factors.len() != 2 || den_scale.is_zero() {
        return None;
    }
    let base = affine_polynomial(ctx, sqrt_radicand, var)?;
    let base_slope = base.coeffs.get(1).cloned()?;
    if base_slope.is_zero() {
        return None;
    }

    for base_idx in 0..2 {
        let Some(base_factor) = Polynomial::from_expr(ctx, polynomial_factors[base_idx], var).ok()
        else {
            continue;
        };
        let Some(base_ratio) = constant_polynomial_ratio(&base, &base_factor) else {
            continue;
        };
        let Some(gap_factor) =
            Polynomial::from_expr(ctx, polynomial_factors[1 - base_idx], var).ok()
        else {
            continue;
        };
        let Some((constant, gap_alignment)) = atanh_gap_constant_and_alignment(&base, &gap_factor)
        else {
            continue;
        };
        let constant_root = exact_rational_sqrt(&constant)?;
        let kernel_scale = num_scale.clone() * base_ratio * gap_alignment / den_scale.clone();
        let scale = -BigRational::from_integer(2.into()) * kernel_scale
            / (constant_root * base_slope.clone());
        return Some(InverseHyperbolicSqrtReciprocalParts {
            base,
            constant,
            scale,
            scale_sqrt_factor: None,
        });
    }

    None
}

fn scaled_asinh_sqrt_reciprocal_parts(
    sqrt_poly: &Polynomial,
    base: &Polynomial,
    num_scale: BigRational,
    den_scale: BigRational,
) -> Option<InverseHyperbolicSqrtReciprocalParts> {
    let base_slope = base.coeffs.get(1).cloned()?;
    let sqrt_slope = sqrt_poly.coeffs.get(1).cloned()?;
    if base_slope.is_zero() || sqrt_slope.is_zero() || den_scale.is_zero() {
        return None;
    }

    let constant = sqrt_slope / base_slope.clone();
    if !constant.is_positive() {
        return None;
    }

    let normalized_sqrt = sqrt_poly.div_scalar(&constant);
    let gap = normalized_sqrt.sub(base);
    if gap.degree() != 0 {
        return None;
    }
    let gap_constant = gap
        .coeffs
        .first()
        .cloned()
        .unwrap_or_else(BigRational::zero);
    if gap_constant != constant {
        return None;
    }

    let kernel_scale = num_scale / den_scale;
    let scale =
        -BigRational::from_integer(2.into()) * kernel_scale / (constant.clone() * base_slope);
    Some(InverseHyperbolicSqrtReciprocalParts {
        base: base.clone(),
        constant,
        scale,
        scale_sqrt_factor: None,
    })
}

fn atanh_expanded_sqrt_var_reciprocal_parts(
    ctx: &Context,
    num_scale: BigRational,
    den: ExprId,
    var: &str,
) -> Option<InverseHyperbolicSqrtReciprocalParts> {
    let (left, right, right_sign) = match ctx.get(den) {
        Expr::Add(left, right) => (*left, *right, BigRational::one()),
        Expr::Sub(left, right) => (*left, *right, BigRational::from_integer((-1).into())),
        _ => return None,
    };

    let (left_scale, left_power) = scaled_var_power_term(ctx, left, var)?;
    let (right_scale, right_power) = scaled_var_power_term(ctx, right, var)?;
    let right_scale = right_scale * right_sign;
    let half = BigRational::new(1.into(), 2.into());
    let three_halves = BigRational::new(3.into(), 2.into());
    let (linear_scale, root_scale) = if left_power == three_halves && right_power == half {
        (left_scale, right_scale)
    } else if left_power == half && right_power == three_halves {
        (right_scale, left_scale)
    } else {
        return None;
    };
    if linear_scale.is_zero() {
        return None;
    }

    let constant = -root_scale / linear_scale.clone();
    if !constant.is_positive() {
        return None;
    }
    let constant_root = exact_rational_sqrt(&constant)?;
    let kernel_scale = num_scale / linear_scale;
    let scale = -BigRational::from_integer(2.into()) * kernel_scale / constant_root;

    Some(InverseHyperbolicSqrtReciprocalParts {
        base: Polynomial::new(
            vec![BigRational::zero(), BigRational::one()],
            var.to_string(),
        ),
        constant,
        scale,
        scale_sqrt_factor: None,
    })
}

fn inverse_hyperbolic_sqrt_reciprocal_parts(
    ctx: &Context,
    expr: ExprId,
    var: &str,
    kind: InverseHyperbolicSqrtReciprocalKind,
) -> Option<InverseHyperbolicSqrtReciprocalParts> {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return None;
    };

    let mut num_scale = BigRational::one();
    let mut numerator_sqrt_radicand = None;
    for factor in mul_leaves(ctx, *num) {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            if numerator_sqrt_radicand.is_some() {
                return None;
            }
            numerator_sqrt_radicand = Some(radicand);
        } else {
            num_scale *= rational_constant_value(ctx, factor)?;
        }
    }

    if numerator_sqrt_radicand.is_none()
        && matches!(kind, InverseHyperbolicSqrtReciprocalKind::Atanh)
    {
        if let Some(parts) =
            atanh_expanded_sqrt_var_reciprocal_parts(ctx, num_scale.clone(), *den, var)
        {
            return Some(parts);
        }
    }

    let mut den_scale = BigRational::one();
    let mut sqrt_radicand = None;
    let mut polynomial_factors = Vec::new();
    for factor in mul_leaves(ctx, *den) {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            if sqrt_radicand.is_some() {
                return None;
            }
            sqrt_radicand = Some(radicand);
        } else if let Some(scale) = rational_constant_value(ctx, factor) {
            den_scale *= scale;
        } else {
            polynomial_factors.push(factor);
        }
    }

    if den_scale.is_zero() {
        return None;
    }

    if let Some(radicand) = numerator_sqrt_radicand {
        if sqrt_radicand.is_none() && matches!(kind, InverseHyperbolicSqrtReciprocalKind::Asinh) {
            return asinh_normalized_sqrt_reciprocal_parts(
                ctx,
                radicand,
                &polynomial_factors,
                num_scale,
                den_scale,
                var,
            );
        }
        if sqrt_radicand.is_none() && matches!(kind, InverseHyperbolicSqrtReciprocalKind::Atanh) {
            return atanh_normalized_sqrt_reciprocal_parts(
                ctx,
                radicand,
                &polynomial_factors,
                num_scale,
                den_scale,
                var,
            );
        }
        return None;
    }

    let sqrt_poly = affine_polynomial(ctx, sqrt_radicand?, var)?;
    let (base, constant) = match kind {
        InverseHyperbolicSqrtReciprocalKind::Asinh => {
            let other_poly = single_affine_factor(ctx, &polynomial_factors, var)?;
            let offset = other_poly
                .coeffs
                .first()
                .cloned()
                .unwrap_or_else(BigRational::zero);
            if offset.is_negative() {
                return None;
            }
            if let Some(constant) = positive_constant_difference(&sqrt_poly, &other_poly) {
                (other_poly, constant)
            } else if offset.is_positive() {
                if let Some(parts) = scaled_asinh_sqrt_reciprocal_parts(
                    &sqrt_poly,
                    &other_poly,
                    num_scale.clone(),
                    den_scale.clone(),
                ) {
                    return Some(parts);
                }
                return None;
            } else {
                return None;
            }
        }
        InverseHyperbolicSqrtReciprocalKind::Atanh => {
            let gap_factor = single_affine_factor(ctx, &polynomial_factors, var)?;
            let (constant, gap_alignment) =
                atanh_gap_constant_and_alignment(&sqrt_poly, &gap_factor)?;
            let slope = sqrt_poly.coeffs.get(1).cloned()?;
            if slope.is_zero() {
                return None;
            }
            let constant_root = exact_rational_sqrt(&constant)?;
            let kernel_scale = num_scale * gap_alignment / den_scale;
            let scale =
                -BigRational::from_integer(2.into()) * kernel_scale / (constant_root * slope);
            let (base, constant) = normalize_atanh_reciprocal_display_base(sqrt_poly, constant);
            return Some(InverseHyperbolicSqrtReciprocalParts {
                base,
                constant,
                scale,
                scale_sqrt_factor: None,
            });
        }
    };

    let slope = base.coeffs.get(1).cloned()?;
    if slope.is_zero() {
        return None;
    }
    let kernel_scale = num_scale / den_scale;
    let scale_without_root = -BigRational::from_integer(2.into()) * kernel_scale / slope;
    let (scale, scale_sqrt_factor) =
        inverse_hyperbolic_scale_over_constant_root(scale_without_root, &constant)?;
    let (base, constant) = if matches!(kind, InverseHyperbolicSqrtReciprocalKind::Asinh) {
        normalize_asinh_reciprocal_display_base(base, constant)
    } else {
        (base, constant)
    };

    Some(InverseHyperbolicSqrtReciprocalParts {
        base,
        constant,
        scale,
        scale_sqrt_factor,
    })
}

fn inverse_hyperbolic_sqrt_reciprocal_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
    kind: InverseHyperbolicSqrtReciprocalKind,
) -> Option<ExprId> {
    let parts = inverse_hyperbolic_sqrt_reciprocal_parts(ctx, expr, var, kind)?;
    let constant = ctx.add(Expr::Number(parts.constant));
    let base = parts.base.to_expr(ctx);
    let quotient = ctx.add(Expr::Div(constant, base));
    let sqrt_arg = ctx.call_builtin(BuiltinFn::Sqrt, vec![quotient]);
    let builtin = match kind {
        InverseHyperbolicSqrtReciprocalKind::Asinh => BuiltinFn::Asinh,
        InverseHyperbolicSqrtReciprocalKind::Atanh => BuiltinFn::Atanh,
    };
    let antiderivative = ctx.call_builtin(builtin, vec![sqrt_arg]);
    if let Some(sqrt_factor) = parts.scale_sqrt_factor {
        scale_rational_sqrt_term(ctx, parts.scale, sqrt_factor, antiderivative)
    } else {
        Some(scale_rational_term(ctx, parts.scale, antiderivative))
    }
}

fn inverse_hyperbolic_sqrt_reciprocal_positive_condition(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
    kind: InverseHyperbolicSqrtReciprocalKind,
) -> Option<ExprId> {
    match ctx.get(expr).clone() {
        Expr::Neg(inner) => {
            return inverse_hyperbolic_sqrt_reciprocal_positive_condition(ctx, inner, var, kind);
        }
        Expr::Mul(left, right) if !contains_named_var(ctx, left, var) => {
            return inverse_hyperbolic_sqrt_reciprocal_positive_condition(ctx, right, var, kind);
        }
        Expr::Mul(left, right) if !contains_named_var(ctx, right, var) => {
            return inverse_hyperbolic_sqrt_reciprocal_positive_condition(ctx, left, var, kind);
        }
        _ => {}
    }

    let parts = inverse_hyperbolic_sqrt_reciprocal_parts(ctx, expr, var, kind)?;
    let condition_poly = match kind {
        InverseHyperbolicSqrtReciprocalKind::Asinh => parts.base,
        InverseHyperbolicSqrtReciprocalKind::Atanh => parts
            .base
            .sub(&Polynomial::new(vec![parts.constant], var.to_string())),
    };
    Some(condition_poly.to_expr(ctx))
}

pub fn integrate_symbolic_is_inverse_hyperbolic_sqrt_reciprocal_target(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> bool {
    inverse_hyperbolic_sqrt_reciprocal_parts(
        ctx,
        expr,
        var,
        InverseHyperbolicSqrtReciprocalKind::Asinh,
    )
    .is_some()
        || inverse_hyperbolic_sqrt_reciprocal_parts(
            ctx,
            expr,
            var,
            InverseHyperbolicSqrtReciprocalKind::Atanh,
        )
        .is_some()
}

fn arctan_sqrt_affine_derivative_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ArctanSqrtAffineDerivativeParts> {
    let mut num_scale = BigRational::one();
    let mut numerator_sqrt_radicand = None;

    for factor in mul_leaves(ctx, num) {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            if numerator_sqrt_radicand.is_some() {
                return None;
            }
            numerator_sqrt_radicand = Some(radicand);
        } else {
            num_scale *= rational_constant_value(ctx, factor)?;
        }
    }

    let mut den_scale = BigRational::one();
    let mut denominator_sqrt_radicand = None;
    let mut polynomial_factors = Vec::new();

    for factor in mul_leaves(ctx, den) {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            if denominator_sqrt_radicand.is_some() {
                return None;
            }
            denominator_sqrt_radicand = Some(radicand);
        } else if let Some(scale) = rational_constant_value(ctx, factor) {
            den_scale *= scale;
        } else {
            polynomial_factors.push(factor);
        }
    }

    if den_scale.is_zero() {
        return None;
    }

    if let Some(radicand) = numerator_sqrt_radicand {
        if denominator_sqrt_radicand.is_some() || polynomial_factors.len() != 2 {
            return None;
        }
        return arctan_sqrt_affine_derivative_parts_from_normalized_factors(
            ctx,
            radicand,
            &polynomial_factors,
            num_scale,
            den_scale,
            var,
        );
    }

    let radicand = denominator_sqrt_radicand?;
    if polynomial_factors.len() != 1 {
        return None;
    }
    arctan_sqrt_affine_derivative_parts_from_direct_factors(
        ctx,
        radicand,
        polynomial_factors[0],
        num_scale,
        den_scale,
        var,
    )
}

fn arctan_sqrt_affine_derivative_parts_from_direct_factors(
    ctx: &Context,
    radicand: ExprId,
    gap_factor: ExprId,
    num_scale: BigRational,
    den_scale: BigRational,
    var: &str,
) -> Option<ArctanSqrtAffineDerivativeParts> {
    let radicand_poly = affine_radicand_polynomial(ctx, radicand, var)?;
    let gap = arctan_sqrt_affine_gap_parts(ctx, &radicand_poly, gap_factor, var)?;
    let kernel_scale = num_scale * gap.kernel_scale_factor.clone() / den_scale;
    let scale =
        arctan_sqrt_affine_output_scale(&radicand_poly, kernel_scale, &gap.denominator_root)?;
    Some(ArctanSqrtAffineDerivativeParts {
        radicand,
        scale,
        argument_scale: gap.argument_scale,
    })
}

fn arctan_sqrt_affine_derivative_parts_from_normalized_factors(
    ctx: &Context,
    radicand: ExprId,
    factors: &[ExprId],
    num_scale: BigRational,
    den_scale: BigRational,
    var: &str,
) -> Option<ArctanSqrtAffineDerivativeParts> {
    let radicand_poly = affine_radicand_polynomial(ctx, radicand, var)?;
    let (radicand_ratio, gap) =
        normalized_affine_radicand_and_gap_parts(ctx, &radicand_poly, factors, var)?;
    let kernel_scale = num_scale * radicand_ratio * gap.kernel_scale_factor.clone() / den_scale;
    let scale =
        arctan_sqrt_affine_output_scale(&radicand_poly, kernel_scale, &gap.denominator_root)?;
    Some(ArctanSqrtAffineDerivativeParts {
        radicand,
        scale,
        argument_scale: gap.argument_scale,
    })
}

fn affine_radicand_polynomial(ctx: &Context, radicand: ExprId, var: &str) -> Option<Polynomial> {
    let poly = Polynomial::from_expr(ctx, radicand, var).ok()?;
    (poly.degree() == 1).then_some(poly)
}

fn polynomial_ratio_to_expr_factor(
    ctx: &Context,
    target: &Polynomial,
    factor: ExprId,
    var: &str,
) -> Option<BigRational> {
    let factor_poly = Polynomial::from_expr(ctx, factor, var).ok()?;
    constant_polynomial_ratio(target, &factor_poly)
}

fn normalized_affine_radicand_and_gap_parts(
    ctx: &Context,
    radicand: &Polynomial,
    factors: &[ExprId],
    var: &str,
) -> Option<(BigRational, ArctanSqrtAffineGapParts)> {
    if factors.len() != 2 {
        return None;
    }

    polynomial_ratio_to_expr_factor(ctx, radicand, factors[0], var)
        .and_then(|radicand_ratio| {
            arctan_sqrt_affine_gap_parts(ctx, radicand, factors[1], var)
                .map(|gap| (radicand_ratio, gap))
        })
        .or_else(|| {
            polynomial_ratio_to_expr_factor(ctx, radicand, factors[1], var).and_then(
                |radicand_ratio| {
                    arctan_sqrt_affine_gap_parts(ctx, radicand, factors[0], var)
                        .map(|gap| (radicand_ratio, gap))
                },
            )
        })
}

fn arctan_sqrt_affine_gap_parts(
    ctx: &Context,
    radicand: &Polynomial,
    gap_factor: ExprId,
    var: &str,
) -> Option<ArctanSqrtAffineGapParts> {
    let gap = Polynomial::from_expr(ctx, gap_factor, var).ok()?;
    if gap.degree() != 1 {
        return None;
    }
    let radicand_slope = radicand.coeffs.get(1).cloned()?;
    if radicand_slope.is_zero() {
        return None;
    }
    let radicand_constant = radicand
        .coeffs
        .first()
        .cloned()
        .unwrap_or_else(BigRational::zero);
    let gap_slope = gap.coeffs.get(1).cloned().unwrap_or_else(BigRational::zero);
    let gap_constant = gap
        .coeffs
        .first()
        .cloned()
        .unwrap_or_else(BigRational::zero);
    let mut radicand_coefficient = gap_slope / radicand_slope;
    let mut offset = gap_constant - radicand_coefficient.clone() * radicand_constant;
    let kernel_scale_factor = if radicand_coefficient.is_negative() && offset.is_negative() {
        radicand_coefficient = -radicand_coefficient;
        offset = -offset;
        -BigRational::one()
    } else {
        BigRational::one()
    };
    if !radicand_coefficient.is_positive() || !offset.is_positive() {
        return None;
    }

    let argument_scale = exact_rational_sqrt(&(radicand_coefficient.clone() / offset.clone()))?;
    let denominator_root = exact_rational_sqrt(&(radicand_coefficient * offset))?;
    Some(ArctanSqrtAffineGapParts {
        argument_scale,
        denominator_root,
        kernel_scale_factor,
    })
}

fn arctan_sqrt_affine_output_scale(
    radicand: &Polynomial,
    kernel_scale: BigRational,
    denominator_root: &BigRational,
) -> Option<BigRational> {
    if kernel_scale.is_zero() || denominator_root.is_zero() {
        return None;
    }
    let slope = radicand.coeffs.get(1).cloned()?;
    if slope.is_zero() {
        return None;
    }
    Some(kernel_scale * BigRational::from_integer(2.into()) / (slope * denominator_root))
}

fn arctan_sqrt_affine_derivative_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let parts = arctan_sqrt_affine_derivative_parts(ctx, num, den, var)?;
    let sqrt = ctx.call_builtin(BuiltinFn::Sqrt, vec![parts.radicand]);
    let arg = scale_factor(ctx, parts.argument_scale, sqrt);
    let arctan = ctx.call_builtin(BuiltinFn::Arctan, vec![arg]);
    Some(scale_factor(ctx, parts.scale, arctan))
}

fn arctan_sqrt_affine_derivative_required_positive_radicand(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return None;
    };
    arctan_sqrt_affine_derivative_parts(ctx, *num, *den, var).map(|parts| parts.radicand)
}

pub fn integrate_symbolic_is_arctan_sqrt_affine_derivative_target(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return false;
    };
    arctan_sqrt_affine_derivative_parts(ctx, *num, *den, var).is_some()
}

pub fn integrate_symbolic_is_arctan_sqrt_var_reciprocal_target(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return false;
    };
    arctan_sqrt_var_positive_linear_parts(ctx, *num, *den, var).is_some()
        || arctan_sqrt_var_symbolic_square_shift_parts(ctx, *num, *den, var).is_some()
}

pub fn integrate_symbolic_is_arctan_sqrt_var_unit_shift_square_target(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> bool {
    integrate_symbolic_arctan_sqrt_var_unit_shift_square_key(ctx, expr, var)
        .is_some_and(|(scale, _)| !scale.is_zero())
}

pub fn integrate_symbolic_arctan_sqrt_var_unit_shift_square_key(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<(BigRational, BigRational)> {
    let Expr::Div(num, den) = ctx.get(expr) else {
        return None;
    };
    let parts = arctan_sqrt_var_unit_shift_square_parts(ctx, *num, *den, var)?;
    (!parts.scale.is_zero()).then_some((parts.scale, parts.offset))
}

fn is_var_square(ctx: &Context, expr: ExprId, var: &str) -> bool {
    match ctx.get(expr) {
        Expr::Pow(base, exp) => is_var(ctx, *base, var) && is_number(ctx, *exp, 2),
        _ => false,
    }
}

fn is_var_square_plus_one(ctx: &Context, expr: ExprId, var: &str) -> bool {
    match ctx.get(expr) {
        Expr::Add(l, r) => {
            (is_var_square(ctx, *l, var) && is_number(ctx, *r, 1))
                || (is_number(ctx, *l, 1) && is_var_square(ctx, *r, var))
        }
        _ => false,
    }
}

fn reciprocal_trig_square_antiderivative(
    ctx: &mut Context,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (builtin, arg) = reciprocal_trig_square_parts(ctx, den)?;
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;

    let integral = match builtin {
        BuiltinFn::Cos => ctx.call_builtin(BuiltinFn::Tan, vec![arg]),
        BuiltinFn::Sin => {
            let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![arg]);
            ctx.add(Expr::Neg(cot_arg))
        }
        _ => return None,
    };

    let is_a_one = if let Expr::Number(n) = ctx.get(a) {
        n.is_one()
    } else {
        false
    };
    if is_a_one {
        Some(integral)
    } else if matches!(builtin, BuiltinFn::Sin) {
        let scaled = ctx.add(Expr::Div(integral, a));
        Some(cas_ast::hold::wrap_hold(ctx, scaled))
    } else {
        Some(ctx.add(Expr::Div(integral, a)))
    }
}

fn trig_square_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    if !is_number(ctx, exp, 2) {
        return None;
    }

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Sin | BuiltinFn::Cos) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let var_expr = ctx.var(var);
    let two = ctx.num(2);
    let half_linear = ctx.add(Expr::Div(var_expr, two));

    let two = ctx.num(2);
    let double_arg = mul2_raw(ctx, two, arg);
    let sin_double = ctx.call_builtin(BuiltinFn::Sin, vec![double_arg]);
    let four = BigRational::from_integer(4.into());
    let oscillatory_scale = match builtin {
        BuiltinFn::Sin => -BigRational::one() / (four * a),
        BuiltinFn::Cos => BigRational::one() / (four * a),
        _ => return None,
    };
    let oscillatory = scale_rational_term(ctx, oscillatory_scale, sin_double);

    Some(ctx.add(Expr::Add(half_linear, oscillatory)))
}

/// `int f(sqrt(x)) dx` for a unary builtin `f`, via the substitution
/// `u = sqrt(x)` (`x = u^2`, `dx = 2u du`):
///
/// ```text
/// int f(sqrt(x)) dx = 2 int u f(u) du = 2 H(sqrt(x)),  H(u) = int u f(u) du
/// ```
///
/// `H` is delegated to the integrator (the monomial-times-{trig, hyperbolic,
/// inverse-trig} owners) and the result is back-substituted `u -> sqrt(x)`.
/// Self-gates to an honest residual if `H` does not resolve (e.g. `f = tan`,
/// where `int u tan(u) du` is non-elementary). Covers sin/cos/sinh/cosh and the
/// inverse-trig family.
fn function_of_sqrt_antiderivative(
    ctx: &mut Context,
    builtin: BuiltinFn,
    arg: ExprId,
    var: &str,
) -> Option<ExprId> {
    // The argument must be sqrt of the bare variable.
    let radicand = sqrt_like_radicand(ctx, arg)?;
    if !is_var(ctx, radicand, var) {
        return None;
    }

    // int f(sqrt(x)) dx = 2 int u f(u) du: delegate the monomial-times-f tail.
    let var_expr = ctx.var(var);
    let f_of_var = ctx.call_builtin(builtin, vec![var_expr]);
    let u_integrand = mul2_raw(ctx, var_expr, f_of_var);
    complete_sqrt_substitution(ctx, u_integrand, arg, var)
}

/// Shared tail of the `u = sqrt(x)` substitution. Given the delegate integrand
/// `u_integrand = u * g(u^2)` (already expressed in the original variable, where
/// `g` is the original integrand), integrate it, back-substitute `u -> sqrt(x)`,
/// fold the nested numeric powers the back-substitution introduces, and scale by
/// 2 (the `dx = 2u du` factor). `sqrt_arg` is the `sqrt(x)` expression to
/// substitute back. Self-gates to an honest residual if the delegated integral
/// does not resolve.
fn complete_sqrt_substitution(
    ctx: &mut Context,
    u_integrand: ExprId,
    sqrt_arg: ExprId,
    var: &str,
) -> Option<ExprId> {
    let h = integrate_symbolic_expr(ctx, u_integrand, var)?;

    let var_expr = ctx.var(var);
    let h_sub = crate::substitute::substitute_power_aware(
        ctx,
        h,
        var_expr,
        sqrt_arg,
        crate::substitute::SubstituteOptions::exact(),
    );
    // The substitution turns x^k into (sqrt(x))^k = Pow(Pow(x,1/2),k); fold those
    // nested numeric powers so the result never displays the ambiguous
    // `x^(1/2)^2` (which re-parses as x^(1/4), not x).
    let h_folded = fold_nested_numeric_powers(ctx, h_sub);
    Some(scale_rational_term(
        ctx,
        BigRational::from_integer(2.into()),
        h_folded,
    ))
}

/// `int e^sqrt(x) dx = 2 (sqrt(x) - 1) e^sqrt(x)`, via `u = sqrt(x)`
/// (`int e^sqrt(x) dx = 2 int u e^u du`). `e^sqrt(x)` is `Pow(E, sqrt(x))`, not a
/// `Function`, so it is dispatched from the Pow arm. Self-gates if the delegated
/// tail `int u e^u du` does not resolve.
fn exp_of_sqrt_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    if !matches!(ctx.get(base), Expr::Constant(Constant::E)) {
        return None;
    }
    let radicand = sqrt_like_radicand(ctx, exp)?;
    if !is_var(ctx, radicand, var) {
        return None;
    }

    // u_integrand = u * e^u.
    let var_expr = ctx.var(var);
    let e = ctx.add(Expr::Constant(Constant::E));
    let e_pow_var = ctx.add(Expr::Pow(e, var_expr));
    let var_expr = ctx.var(var);
    let u_integrand = mul2_raw(ctx, var_expr, e_pow_var);
    complete_sqrt_substitution(ctx, u_integrand, exp, var)
}

/// `int H(sqrt(x)) / sqrt(x) dx = 2 int H(u) du`, via `u = sqrt(x)`: the
/// `1/sqrt(x)` cofactor cancels the `u` from `dx = 2u du`, so the delegate
/// integrand is just `H(u)`. The engine normalizes `H(sqrt(x))/sqrt(x)` to the
/// product `H(sqrt(x)) * x^(-1/2)`, so this is dispatched from the Mul arm with
/// the two factors. Covers `H = exp` (`Pow(E, .)`) and the unary builtins whose
/// primitive resolves (e.g. `int e^sqrt(x)/sqrt(x) = 2 e^sqrt(x)`,
/// `int sin(sqrt(x))/sqrt(x) = -2 cos(sqrt(x))`). Self-gates otherwise.
fn function_over_sqrt_antiderivative(
    ctx: &mut Context,
    factor_a: ExprId,
    factor_b: ExprId,
    var: &str,
) -> Option<ExprId> {
    // One factor must be the reciprocal root x^(-1/2); the other is H(sqrt(x)).
    let h_expr = if is_negative_half_power_of_var(ctx, factor_a, var) {
        factor_b
    } else if is_negative_half_power_of_var(ctx, factor_b, var) {
        factor_a
    } else {
        return None;
    };
    let (h_of_var, sqrt_arg) = function_of_sqrt_parts(ctx, h_expr, var)?;
    // u_integrand = u * (H(u)/u) = H(u); back-substitute against the sqrt(x) arg.
    complete_sqrt_substitution(ctx, h_of_var, sqrt_arg, var)
}

/// `int H(sqrt(x)) / sqrt(x) dx` when the integrand survives as a literal
/// `Div(H(sqrt(x)), sqrt(x))` (e.g. on recursive integrator entry, before the
/// `A/sqrt(x) -> A*x^(-1/2)` normalization). Same `u = sqrt(x)` reduction as the
/// Mul form: `2 int H(u) du`.
fn function_over_sqrt_div_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let den_radicand = sqrt_like_radicand(ctx, den)?;
    if !is_var(ctx, den_radicand, var) {
        return None;
    }
    let (h_of_var, sqrt_arg) = function_of_sqrt_parts(ctx, num, var)?;
    complete_sqrt_substitution(ctx, h_of_var, sqrt_arg, var)
}

/// If `h_expr` is `H(sqrt(x))` for `H = exp` (`Pow(E, .)`) or a unary builtin,
/// return `(H(u) rebuilt in the original variable, the sqrt(x) argument)`.
fn function_of_sqrt_parts(
    ctx: &mut Context,
    h_expr: ExprId,
    var: &str,
) -> Option<(ExprId, ExprId)> {
    let arg_is_sqrt_var = |ctx: &mut Context, a: ExprId| {
        sqrt_like_radicand(ctx, a).is_some_and(|r| is_var(ctx, r, var))
    };
    let var_expr = ctx.var(var);
    match ctx.get(h_expr).clone() {
        Expr::Pow(base, exp)
            if matches!(ctx.get(base), Expr::Constant(Constant::E))
                && arg_is_sqrt_var(ctx, exp) =>
        {
            let e = ctx.add(Expr::Constant(Constant::E));
            Some((ctx.add(Expr::Pow(e, var_expr)), exp))
        }
        Expr::Function(fn_id, args) if args.len() == 1 && arg_is_sqrt_var(ctx, args[0]) => {
            let builtin = ctx.builtin_of(fn_id)?;
            Some((ctx.call_builtin(builtin, vec![var_expr]), args[0]))
        }
        _ => None,
    }
}

/// Whether `expr` is `x^(-1/2)` (the reciprocal square root of the bare variable).
fn is_negative_half_power_of_var(ctx: &Context, expr: ExprId, var: &str) -> bool {
    match ctx.get(expr) {
        Expr::Pow(base, exp) => is_var(ctx, *base, var) && is_negative_half(ctx, *exp),
        _ => false,
    }
}

/// Fold `Pow(Pow(b, p), q) -> Pow(b, p*q)` for numeric `p, q` (and `Pow(b, 1) ->
/// b`) throughout an expression. Used to collapse `(sqrt(x))^k = x^(k/2)` left by
/// a `u = sqrt(x)` back-substitution, which the generic normalizer keeps nested
/// for fractional inner exponents.
fn fold_nested_numeric_powers(ctx: &mut Context, expr: ExprId) -> ExprId {
    match ctx.get(expr).clone() {
        Expr::Pow(base, exp) => {
            let base = fold_nested_numeric_powers(ctx, base);
            let exp = fold_nested_numeric_powers(ctx, exp);
            if let Expr::Pow(inner_base, inner_exp) = ctx.get(base).clone() {
                // Accept either a literal Number or a folded rational such as
                // Div(1, 2) for the exponents.
                if let (Some(p), Some(q)) = (
                    crate::numeric_eval::as_rational_const(ctx, inner_exp),
                    crate::numeric_eval::as_rational_const(ctx, exp),
                ) {
                    let product = &p * &q;
                    if product.is_one() {
                        return inner_base;
                    }
                    let new_exp = ctx.add(Expr::Number(product));
                    return ctx.add(Expr::Pow(inner_base, new_exp));
                }
            }
            ctx.add(Expr::Pow(base, exp))
        }
        Expr::Add(l, r) => {
            let l = fold_nested_numeric_powers(ctx, l);
            let r = fold_nested_numeric_powers(ctx, r);
            ctx.add(Expr::Add(l, r))
        }
        Expr::Sub(l, r) => {
            let l = fold_nested_numeric_powers(ctx, l);
            let r = fold_nested_numeric_powers(ctx, r);
            ctx.add(Expr::Sub(l, r))
        }
        Expr::Mul(l, r) => {
            let l = fold_nested_numeric_powers(ctx, l);
            let r = fold_nested_numeric_powers(ctx, r);
            mul2_raw(ctx, l, r)
        }
        Expr::Div(l, r) => {
            let l = fold_nested_numeric_powers(ctx, l);
            let r = fold_nested_numeric_powers(ctx, r);
            ctx.add(Expr::Div(l, r))
        }
        Expr::Neg(inner) => {
            let inner = fold_nested_numeric_powers(ctx, inner);
            ctx.add(Expr::Neg(inner))
        }
        Expr::Function(fn_id, args) => {
            let new_args: Vec<ExprId> = args
                .iter()
                .map(|&a| fold_nested_numeric_powers(ctx, a))
                .collect();
            ctx.add(Expr::Function(fn_id, new_args))
        }
        _ => expr,
    }
}

/// `int inv(x)/x^n dx` (integer `n >= 2`) for an inverse-trig `inv` of the bare
/// variable, by parts (`u = inv(x)`, `dv = x^-n dx`, `v = -1/((n-1) x^(n-1))`):
///
/// ```text
/// int inv(x)/x^n dx = -inv(x)/((n-1) x^(n-1)) + 1/(n-1) int inv'(x)/x^(n-1) dx
/// ```
///
/// The lower-degree tail is delegated to the integrator: for `arctan` it is
/// `int 1/(x^(n-1)(1+x^2))` and for `arcsin`/`arccos` it is
/// `int 1/(x^(n-1) sqrt(1-x^2))`. If the tail does not resolve the whole rule
/// self-gates to an honest residual.
fn inverse_trig_over_power_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    // Denominator must be x^n with n >= 2 a small integer.
    let Expr::Pow(base, exp) = ctx.get(den).clone() else {
        return None;
    };
    if !is_var(ctx, base, var) {
        return None;
    }
    let n = match ctx.get(exp) {
        Expr::Number(value) if value.is_integer() => value.to_integer().to_i64()?,
        _ => return None,
    };
    if !(2..=8).contains(&n) {
        return None;
    }

    // Numerator must be a single inverse-trig of the bare variable.
    let Expr::Function(fn_id, args) = ctx.get(num).clone() else {
        return None;
    };
    if args.len() != 1 || !is_var(ctx, args[0], var) {
        return None;
    }
    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(
        builtin,
        BuiltinFn::Arcsin
            | BuiltinFn::Asin
            | BuiltinFn::Arccos
            | BuiltinFn::Acos
            | BuiltinFn::Arctan
            | BuiltinFn::Atan
    ) {
        return None;
    }

    // x^(n-1) (just x when n == 2).
    let lower_power = if n == 2 {
        ctx.var(var)
    } else {
        let var_expr = ctx.var(var);
        let exp_expr = ctx.num(n - 1);
        ctx.add(Expr::Pow(var_expr, exp_expr))
    };
    let inv_scale = BigRational::new(1.into(), (n - 1).into()); // 1/(n-1)

    // head = -1/(n-1) * inv(x)/x^(n-1)
    let head_div = ctx.add(Expr::Div(num, lower_power));
    let head = scale_rational_term(ctx, -inv_scale.clone(), head_div);

    // tail integrand = inv'(x)/x^(n-1), flattened to a single fraction (the
    // internal integrator does not pre-simplify a nested `(N/D)/x^(n-1)`).
    let derivative =
        crate::symbolic_differentiation_support::differentiate_symbolic_expr(ctx, num, var)?;
    let tail_integrand = match ctx.get(derivative).clone() {
        Expr::Div(num_d, den_d) => {
            let denom = ctx.add(Expr::Mul(den_d, lower_power));
            ctx.add(Expr::Div(num_d, denom))
        }
        _ => ctx.add(Expr::Div(derivative, lower_power)),
    };
    let tail = integrate_symbolic_expr(ctx, tail_integrand, var)?;
    let scaled_tail = scale_rational_term(ctx, inv_scale, tail);

    Some(ctx.add(Expr::Add(head, scaled_tail)))
}

/// Antiderivative of `arcsin(a x + b)^2` and `arccos(a x + b)^2`.
///
/// Both are elementary (integration by parts, twice). With `u = a x + b`,
///
/// ```text
/// G(u) = u·arcsin(u)^2 − 2u + 2·sqrt(1 − u²)·arcsin(u)        (arcsin)
/// G(u) = u·arccos(u)^2 − 2u − 2·sqrt(1 − u²)·arccos(u)        (arccos)
/// ```
///
/// and the antiderivative in `x` is `(1/a)·G(a x + b)`, since
/// `d/dx[(1/a)·G(a x + b)] = G'(a x + b) = inv(a x + b)^2`.  The only branch
/// difference between the two is the sign of the `sqrt` term.
///
/// `arctan(x)^2` is deliberately NOT handled: it is non-elementary (it reduces
/// to `∫ln(cos θ) dθ`), so it must stay an honest residual.
fn inverse_trig_square_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    if !is_number(ctx, exp, 2) {
        return None;
    }

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(
        builtin,
        BuiltinFn::Arcsin | BuiltinFn::Asin | BuiltinFn::Arccos | BuiltinFn::Acos
    ) {
        return None;
    }

    let arg = args[0];
    let (a_expr, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a_expr)?;
    if a.is_zero() {
        return None;
    }

    // head = arg·inv(arg)^2
    let inv = ctx.call_builtin(builtin, vec![arg]);
    let two = ctx.num(2);
    let inv_sq = ctx.add(Expr::Pow(inv, two));
    let head = mul2_raw(ctx, arg, inv_sq);

    // linear = −2·arg  (the −2/a·u part of G scaled back by 1/a gives −2x; the
    // constant offset folds into the integration constant)
    let linear = scale_rational_term(ctx, -BigRational::from_integer(2.into()), arg);

    // sqrt_signed = ±2·sqrt(1 − arg²)·inv(arg)
    let radicand = unit_minus_square(ctx, arg);
    let sqrt_term = ctx.call_builtin(BuiltinFn::Sqrt, vec![radicand]);
    let sqrt_product = mul2_raw(ctx, sqrt_term, inv);
    let sqrt_scale = match builtin {
        BuiltinFn::Arcsin | BuiltinFn::Asin => BigRational::from_integer(2.into()),
        _ => -BigRational::from_integer(2.into()),
    };
    let sqrt_signed = scale_rational_term(ctx, sqrt_scale, sqrt_product);

    let head_plus_linear = ctx.add(Expr::Add(head, linear));
    let g = ctx.add(Expr::Add(head_plus_linear, sqrt_signed));

    let scale = BigRational::one() / a;
    Some(scale_rational_term(ctx, scale, g))
}

fn trig_ratio_square_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    if !is_number(ctx, exp, 2) {
        return None;
    }

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Tan | BuiltinFn::Cot) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    Some(trig_ratio_square_antiderivative_from_parts(
        ctx,
        TrigRatioSquareParts { builtin, arg, a },
        var,
    ))
}

fn trig_tan_cot_odd_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    let power = if is_number(ctx, exp, 3) {
        3
    } else if is_number(ctx, exp, 5) {
        5
    } else {
        return None;
    };
    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };
    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Tan | BuiltinFn::Cot) {
        return None;
    }
    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }
    Some(match (builtin, power) {
        (BuiltinFn::Tan, 3) => trig_tan_third_antiderivative_from_parts(ctx, arg, a),
        (BuiltinFn::Tan, _) => trig_tan_fifth_antiderivative_from_parts(ctx, arg, a),
        (_, 3) => trig_cot_third_antiderivative_from_parts(ctx, arg, a),
        _ => trig_cot_fifth_antiderivative_from_parts(ctx, arg, a),
    })
}

