fn hyperbolic_square_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    if !is_number(ctx, exp, 2) {
        return None;
    }

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Sinh | BuiltinFn::Cosh | BuiltinFn::Tanh) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    if matches!(builtin, BuiltinFn::Tanh) {
        let var_expr = ctx.var(var);
        let tanh_arg = ctx.call_builtin(BuiltinFn::Tanh, vec![arg]);
        let correction = scale_rational_term(ctx, -BigRational::one() / a, tanh_arg);
        return Some(ctx.add(Expr::Add(var_expr, correction)));
    }

    let sinh_arg = ctx.call_builtin(BuiltinFn::Sinh, vec![arg]);
    let cosh_arg = ctx.call_builtin(BuiltinFn::Cosh, vec![arg]);
    let product = mul2_raw(ctx, sinh_arg, cosh_arg);
    let two_scale = BigRational::from_integer(2.into());
    let oscillatory = scale_rational_term(ctx, BigRational::one() / (two_scale * a), product);

    let var_expr = ctx.var(var);
    let two = ctx.num(2);
    let half_linear = ctx.add(Expr::Div(var_expr, two));

    match builtin {
        BuiltinFn::Sinh => Some(ctx.add(Expr::Sub(oscillatory, half_linear))),
        BuiltinFn::Cosh => Some(ctx.add(Expr::Add(oscillatory, half_linear))),
        _ => None,
    }
}

fn hyperbolic_tanh_even_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    let power = if is_number(ctx, exp, 4) {
        4
    } else if is_number(ctx, exp, 6) {
        6
    } else if is_number(ctx, exp, 8) {
        8
    } else {
        return None;
    };

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };
    if ctx.builtin_of(fn_id) != Some(BuiltinFn::Tanh) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let tanh_arg = ctx.call_builtin(BuiltinFn::Tanh, vec![arg]);
    let three = ctx.num(3);
    let tanh_cubed = ctx.add(Expr::Pow(tanh_arg, three));
    let cubic_term = scale_rational_term(ctx, BigRational::new(1.into(), 3.into()), tanh_cubed);
    let mut tanh_terms = ctx.add(Expr::Add(tanh_arg, cubic_term));
    if power >= 6 {
        let five = ctx.num(5);
        let tanh_fifth = ctx.add(Expr::Pow(tanh_arg, five));
        let fifth_term = scale_rational_term(ctx, BigRational::new(1.into(), 5.into()), tanh_fifth);
        tanh_terms = ctx.add(Expr::Add(tanh_terms, fifth_term));
    }
    if power == 8 {
        let seven = ctx.num(7);
        let tanh_seventh = ctx.add(Expr::Pow(tanh_arg, seven));
        let seventh_term =
            scale_rational_term(ctx, BigRational::new(1.into(), 7.into()), tanh_seventh);
        tanh_terms = ctx.add(Expr::Add(tanh_terms, seventh_term));
    }
    let var_expr = ctx.var(var);
    let primitive = if a.is_negative() {
        let scaled_tanh_terms = if power == 8 {
            scale_reciprocal_integration_result_preserving_presentation(
                ctx,
                -BigRational::one() / a,
                tanh_terms,
            )
        } else {
            scale_rational_term(ctx, -BigRational::one() / a, tanh_terms)
        };
        ctx.add(Expr::Add(var_expr, scaled_tanh_terms))
    } else {
        let scaled_tanh_terms = if a.is_one() {
            tanh_terms
        } else if power == 8 {
            scale_reciprocal_integration_result_preserving_presentation(
                ctx,
                BigRational::one() / a,
                tanh_terms,
            )
        } else {
            scale_rational_term(ctx, BigRational::one() / a, tanh_terms)
        };
        ctx.add(Expr::Sub(var_expr, scaled_tanh_terms))
    };
    if power == 8 {
        Some(cas_ast::hold::wrap_hold(ctx, primitive))
    } else {
        Some(primitive)
    }
}

pub fn integrate_symbolic_is_affine_hyperbolic_square_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Pow(base, exp) = ctx.get(expr).clone() else {
        return false;
    };
    hyperbolic_square_affine_antiderivative(ctx, base, exp, var).is_some()
}

pub fn integrate_symbolic_is_affine_hyperbolic_cubic_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Pow(base, exp) = ctx.get(expr).clone() else {
        return false;
    };
    is_number(ctx, exp, 3)
        && hyperbolic_odd_power_limited_affine_antiderivative(ctx, base, exp, var).is_some()
}

pub fn integrate_symbolic_is_affine_hyperbolic_fifth_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Pow(base, exp) = ctx.get(expr).clone() else {
        return false;
    };
    let Expr::Function(_, args) = ctx.get(base).clone() else {
        return false;
    };
    if args.len() != 1 || is_var(ctx, args[0], var) {
        return false;
    }
    is_number(ctx, exp, 5)
        && hyperbolic_odd_power_limited_affine_antiderivative(ctx, base, exp, var).is_some()
}

pub fn integrate_symbolic_is_affine_hyperbolic_seventh_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let Expr::Pow(base, exp) = ctx.get(expr).clone() else {
        return false;
    };
    let Expr::Function(_, args) = ctx.get(base).clone() else {
        return false;
    };
    if args.len() != 1 {
        return false;
    }
    is_number(ctx, exp, 7)
        && hyperbolic_odd_power_limited_affine_antiderivative(ctx, base, exp, var).is_some()
}

fn hyperbolic_square_product_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut sinh_arg = None;
    let mut cosh_arg = None;

    for factor in factors {
        if let Some(value) = rational_constant_value(ctx, factor) {
            scale *= value;
            continue;
        }

        if let Some(arg) = squared_unary_builtin_arg(ctx, factor, BuiltinFn::Sinh) {
            if sinh_arg.replace(arg).is_some() {
                return None;
            }
            continue;
        }

        if let Some(arg) = squared_unary_builtin_arg(ctx, factor, BuiltinFn::Cosh) {
            if cosh_arg.replace(arg).is_some() {
                return None;
            }
            continue;
        }

        return None;
    }

    if scale.is_zero() {
        return None;
    }

    let sinh_arg = sinh_arg?;
    let cosh_arg = cosh_arg?;
    if compare_expr(ctx, sinh_arg, cosh_arg) != Ordering::Equal {
        return None;
    }

    let (a, _) = get_linear_coeffs(ctx, sinh_arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let four = ctx.num(4);
    let quadruple_arg = mul2_raw(ctx, four, sinh_arg);
    let sinh_quadruple = ctx.call_builtin(BuiltinFn::Sinh, vec![quadruple_arg]);
    let oscillatory = scale_rational_term(
        ctx,
        scale.clone() / (BigRational::from_integer(32.into()) * a),
        sinh_quadruple,
    );
    let var_expr = ctx.var(var);
    let linear = scale_rational_term(ctx, scale / BigRational::from_integer(8.into()), var_expr);

    Some(ctx.add(Expr::Sub(oscillatory, linear)))
}

pub fn integrate_symbolic_is_hyperbolic_square_product_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    hyperbolic_square_product_antiderivative(ctx, expr, var).is_some()
}

struct TrigRatioSquareParts {
    builtin: BuiltinFn,
    arg: ExprId,
    a: BigRational,
}

fn trig_ratio_square_antiderivative_from_parts(
    ctx: &mut Context,
    parts: TrigRatioSquareParts,
    var: &str,
) -> ExprId {
    let primitive = match parts.builtin {
        BuiltinFn::Tan => ctx.call_builtin(BuiltinFn::Tan, vec![parts.arg]),
        BuiltinFn::Cot => {
            let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![parts.arg]);
            ctx.add(Expr::Neg(cot_arg))
        }
        _ => unreachable!("only tan/cot ratio squares have a primitive"),
    };
    let scaled_primitive = if parts.a.is_one() {
        primitive
    } else {
        let a = ctx.add(Expr::Number(parts.a));
        let scaled = ctx.add(Expr::Div(primitive, a));
        if matches!(parts.builtin, BuiltinFn::Cot) {
            cas_ast::hold::wrap_hold(ctx, scaled)
        } else {
            scaled
        }
    };
    let var_expr = ctx.var(var);
    ctx.add(Expr::Sub(scaled_primitive, var_expr))
}

fn trig_abs_log_term(ctx: &mut Context, builtin: BuiltinFn, arg: ExprId) -> ExprId {
    let inner = ctx.call_builtin(builtin, vec![arg]);
    let abs_inner = ctx.call_builtin(BuiltinFn::Abs, vec![inner]);
    ctx.call_builtin(BuiltinFn::Ln, vec![abs_inner])
}

fn trig_tan_third_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
) -> ExprId {
    // d/du [tan^2(u)/2 + ln|cos(u)|] = tan^3(u).
    let tan_arg = ctx.call_builtin(BuiltinFn::Tan, vec![arg]);
    let two = ctx.num(2);
    let tan_squared = ctx.add(Expr::Pow(tan_arg, two));
    let square = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / (BigRational::from_integer(2.into()) * a.clone()),
        tan_squared,
    );
    let log_raw = trig_abs_log_term(ctx, BuiltinFn::Cos, arg);
    let log_term = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / a,
        log_raw,
    );
    ctx.add(Expr::Add(square, log_term))
}

fn trig_cot_third_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
) -> ExprId {
    // d/du [-cot^2(u)/2 - ln|sin(u)|] = cot^3(u).
    let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![arg]);
    let two = ctx.num(2);
    let cot_squared = ctx.add(Expr::Pow(cot_arg, two));
    let square = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / (BigRational::from_integer(2.into()) * a.clone()),
        cot_squared,
    );
    let log_raw = trig_abs_log_term(ctx, BuiltinFn::Sin, arg);
    let log_term = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / a,
        log_raw,
    );
    ctx.add(Expr::Add(square, log_term))
}

fn trig_tan_fifth_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
) -> ExprId {
    // d/du [tan^4(u)/4 - tan^2(u)/2 - ln|cos(u)|] = tan^5(u).
    // Built in expanded sin/cos form: Pow(Tan, 4) sends the
    // post-integration rewrite into a non-terminating tan <-> sin/cos
    // ping-pong (cot^4 forms do not loop).
    let sin_arg = ctx.call_builtin(BuiltinFn::Sin, vec![arg]);
    let cos_arg = ctx.call_builtin(BuiltinFn::Cos, vec![arg]);
    let four = ctx.num(4);
    let two = ctx.num(2);
    let sin_fourth = ctx.add(Expr::Pow(sin_arg, four));
    let cos_fourth = ctx.add(Expr::Pow(cos_arg, four));
    let sin_squared = ctx.add(Expr::Pow(sin_arg, two));
    let cos_squared = ctx.add(Expr::Pow(cos_arg, two));
    let tan_fourth = ctx.add(Expr::Div(sin_fourth, cos_fourth));
    let tan_squared = ctx.add(Expr::Div(sin_squared, cos_squared));
    let quartic = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / (BigRational::from_integer(4.into()) * a.clone()),
        tan_fourth,
    );
    let square = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / (BigRational::from_integer(2.into()) * a.clone()),
        tan_squared,
    );
    let log_raw = trig_abs_log_term(ctx, BuiltinFn::Cos, arg);
    let log_term = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / a,
        log_raw,
    );
    let head = ctx.add(Expr::Add(quartic, square));
    ctx.add(Expr::Add(head, log_term))
}

fn trig_cot_fifth_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
) -> ExprId {
    // d/du [-cot^4(u)/4 + cot^2(u)/2 + ln|sin(u)|] = cot^5(u).
    let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![arg]);
    let four = ctx.num(4);
    let two = ctx.num(2);
    let cot_fourth = ctx.add(Expr::Pow(cot_arg, four));
    let cot_squared = ctx.add(Expr::Pow(cot_arg, two));
    let quartic = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / (BigRational::from_integer(4.into()) * a.clone()),
        cot_fourth,
    );
    let square = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / (BigRational::from_integer(2.into()) * a.clone()),
        cot_squared,
    );
    let log_raw = trig_abs_log_term(ctx, BuiltinFn::Sin, arg);
    let log_term = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / a,
        log_raw,
    );
    let head = ctx.add(Expr::Add(quartic, square));
    ctx.add(Expr::Add(head, log_term))
}

fn trig_tan_fourth_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
    var: &str,
) -> ExprId {
    let tan_arg = ctx.call_builtin(BuiltinFn::Tan, vec![arg]);
    let three = ctx.num(3);
    let tan_cubed = ctx.add(Expr::Pow(tan_arg, three));
    let cubic = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / (BigRational::from_integer(3.into()) * a.clone()),
        tan_cubed,
    );
    let linear_tan = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / a,
        tan_arg,
    );
    let variable = ctx.var(var);
    let tan_terms = ctx.add(Expr::Add(cubic, linear_tan));
    ctx.add(Expr::Add(tan_terms, variable))
}

fn trig_cot_fourth_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
    var: &str,
) -> ExprId {
    let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![arg]);
    let three = ctx.num(3);
    let cot_cubed = ctx.add(Expr::Pow(cot_arg, three));
    let variable = ctx.var(var);

    if a.is_positive() {
        let linear = scale_reciprocal_integration_result_preserving_presentation(
            ctx,
            BigRational::one() / a.clone(),
            cot_arg,
        );
        let cubic = scale_reciprocal_integration_result_preserving_presentation(
            ctx,
            BigRational::one() / (BigRational::from_integer(3.into()) * a),
            cot_cubed,
        );
        let variable_plus_linear = ctx.add(Expr::Add(variable, linear));
        return ctx.add(Expr::Sub(variable_plus_linear, cubic));
    }

    let linear = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / a.clone(),
        cot_arg,
    );
    let cubic = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / (BigRational::from_integer(3.into()) * a),
        cot_cubed,
    );
    let variable_minus_linear = ctx.add(Expr::Sub(variable, linear));
    ctx.add(Expr::Add(variable_minus_linear, cubic))
}

fn trig_tan_sixth_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    a: BigRational,
    var: &str,
) -> ExprId {
    let tan_arg = ctx.call_builtin(BuiltinFn::Tan, vec![arg]);
    let three = ctx.num(3);
    let five = ctx.num(5);
    let tan_cubed = ctx.add(Expr::Pow(tan_arg, three));
    let tan_fifth = ctx.add(Expr::Pow(tan_arg, five));
    let fifth = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / (BigRational::from_integer(5.into()) * a.clone()),
        tan_fifth,
    );
    let cubic = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        -BigRational::one() / (BigRational::from_integer(3.into()) * a.clone()),
        tan_cubed,
    );
    let linear = scale_reciprocal_integration_result_preserving_presentation(
        ctx,
        BigRational::one() / a,
        tan_arg,
    );
    let first_two = ctx.add(Expr::Add(fifth, cubic));
    let tan_terms = ctx.add(Expr::Add(first_two, linear));
    let variable = ctx.var(var);
    ctx.add(Expr::Sub(tan_terms, variable))
}

