fn trig_sine_cosine_same_affine_product_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut sin_arg = None;
    let mut cos_arg = None;

    for factor in factors {
        match ctx.get(factor) {
            Expr::Function(fn_id, args)
                if args.len() == 1 && ctx.builtin_of(*fn_id) == Some(BuiltinFn::Sin) =>
            {
                if sin_arg.replace(args[0]).is_some() {
                    return None;
                }
            }
            Expr::Function(fn_id, args)
                if args.len() == 1 && ctx.builtin_of(*fn_id) == Some(BuiltinFn::Cos) =>
            {
                if cos_arg.replace(args[0]).is_some() {
                    return None;
                }
            }
            _ => scale *= rational_constant_value(ctx, factor)?,
        }
    }

    let sin_arg = sin_arg?;
    let cos_arg = cos_arg?;
    if compare_expr(ctx, sin_arg, cos_arg) != Ordering::Equal {
        return None;
    }

    let (a, _) = get_linear_coeffs(ctx, sin_arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let sin = ctx.call_builtin(BuiltinFn::Sin, vec![sin_arg]);
    let two = ctx.num(2);
    let sin_squared = ctx.add(Expr::Pow(sin, two));
    Some(scale_rational_term(
        ctx,
        scale / BigRational::from_integer(2.into()) / a,
        sin_squared,
    ))
}

fn trig_power_times_derivative_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut powered: Option<(BuiltinFn, ExprId, i64)> = None;
    let mut derivative_factor: Option<(BuiltinFn, ExprId)> = None;

    for factor in factors {
        match ctx.get(factor).clone() {
            Expr::Pow(base, exp) => {
                let (fn_id, args) = match ctx.get(base).clone() {
                    Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
                    _ => {
                        scale *= rational_constant_value(ctx, factor)?;
                        continue;
                    }
                };
                let builtin = ctx.builtin_of(fn_id)?;
                if !matches!(builtin, BuiltinFn::Sin | BuiltinFn::Cos) {
                    scale *= rational_constant_value(ctx, factor)?;
                    continue;
                }
                let power = bounded_positive_integer_power(ctx, exp, 2, 5)?;
                if powered.replace((builtin, args[0], power)).is_some() {
                    return None;
                }
            }
            Expr::Function(fn_id, args) if args.len() == 1 => match ctx.builtin_of(fn_id) {
                Some(builtin @ (BuiltinFn::Sin | BuiltinFn::Cos)) => {
                    if derivative_factor.replace((builtin, args[0])).is_some() {
                        return None;
                    }
                }
                _ => scale *= rational_constant_value(ctx, factor)?,
            },
            _ => scale *= rational_constant_value(ctx, factor)?,
        }
    }

    let (powered_builtin, powered_arg, power) = powered?;
    let (derivative_builtin, derivative_arg) = derivative_factor?;
    if compare_expr(ctx, powered_arg, derivative_arg) != Ordering::Equal {
        return None;
    }

    let sign = match (powered_builtin, derivative_builtin) {
        (BuiltinFn::Sin, BuiltinFn::Cos) => BigRational::one(),
        (BuiltinFn::Cos, BuiltinFn::Sin) => -BigRational::one(),
        _ => return None,
    };

    let (a, _) = get_linear_coeffs(ctx, powered_arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let base = ctx.call_builtin(powered_builtin, vec![powered_arg]);
    let next_power = ctx.num(power + 1);
    let primitive = ctx.add(Expr::Pow(base, next_power));
    let denominator = BigRational::from_integer((power + 1).into()) * a;
    Some(scale_rational_term(
        ctx,
        sign * scale / denominator,
        primitive,
    ))
}

fn trig_fourth_power_affine_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (builtin, arg, power) = trig_power_base(ctx, expr, 4, 4)?;
    if power != 4 {
        return None;
    }

    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let var_expr = ctx.var(var);
    let var_term = scale_rational_term(ctx, BigRational::new(3.into(), 8.into()), var_expr);

    let two = ctx.num(2);
    let four = ctx.num(4);
    let double_arg = mul2_raw(ctx, two, arg);
    let quadruple_arg = mul2_raw(ctx, four, arg);
    let sin_double = ctx.call_builtin(BuiltinFn::Sin, vec![double_arg]);
    let sin_quadruple = ctx.call_builtin(BuiltinFn::Sin, vec![quadruple_arg]);

    let double_scale = BigRational::new(1.into(), 4.into()) / a.clone();
    let signed_double_scale = match builtin {
        BuiltinFn::Sin => -double_scale,
        BuiltinFn::Cos => double_scale,
        _ => return None,
    };
    let double_term = scale_rational_term(ctx, signed_double_scale, sin_double);
    let quadruple_term = scale_rational_term(
        ctx,
        BigRational::new(1.into(), 32.into()) / a,
        sin_quadruple,
    );

    let first = ctx.add(Expr::Add(var_term, double_term));
    let primitive = ctx.add(Expr::Add(first, quadruple_term));
    Some(cas_ast::hold::wrap_hold(ctx, primitive))
}

fn trig_sixth_power_affine_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (builtin, arg, power) = trig_power_base(ctx, expr, 6, 6)?;
    if power != 6 {
        return None;
    }

    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let var_expr = ctx.var(var);
    let var_term = scale_rational_term(ctx, BigRational::new(5.into(), 16.into()), var_expr);

    let two = ctx.num(2);
    let four = ctx.num(4);
    let six = ctx.num(6);
    let double_arg = mul2_raw(ctx, two, arg);
    let quadruple_arg = mul2_raw(ctx, four, arg);
    let sextuple_arg = mul2_raw(ctx, six, arg);
    let sin_double = ctx.call_builtin(BuiltinFn::Sin, vec![double_arg]);
    let sin_quadruple = ctx.call_builtin(BuiltinFn::Sin, vec![quadruple_arg]);
    let sin_sextuple = ctx.call_builtin(BuiltinFn::Sin, vec![sextuple_arg]);

    let double_scale = BigRational::new(15.into(), 64.into()) / a.clone();
    let signed_double_scale = match builtin {
        BuiltinFn::Sin => -double_scale,
        BuiltinFn::Cos => double_scale,
        _ => return None,
    };
    let sextuple_scale = BigRational::new(1.into(), 192.into()) / a.clone();
    let signed_sextuple_scale = match builtin {
        BuiltinFn::Sin => -sextuple_scale,
        BuiltinFn::Cos => sextuple_scale,
        _ => return None,
    };

    let double_term = scale_rational_term(ctx, signed_double_scale, sin_double);
    let quadruple_term = scale_rational_term(
        ctx,
        BigRational::new(3.into(), 64.into()) / a,
        sin_quadruple,
    );
    let sextuple_term = scale_rational_term(ctx, signed_sextuple_scale, sin_sextuple);

    let first = ctx.add(Expr::Add(var_term, double_term));
    let second = ctx.add(Expr::Add(first, quadruple_term));
    let primitive = ctx.add(Expr::Add(second, sextuple_term));
    Some(cas_ast::hold::wrap_hold(ctx, primitive))
}

fn trig_eighth_power_affine_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (builtin, arg, power) = trig_power_base(ctx, expr, 8, 8)?;
    if power != 8 {
        return None;
    }

    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let var_expr = ctx.var(var);
    let var_term = scale_rational_term(ctx, BigRational::new(35.into(), 128.into()), var_expr);

    let two = ctx.num(2);
    let four = ctx.num(4);
    let six = ctx.num(6);
    let eight = ctx.num(8);
    let double_arg = mul2_raw(ctx, two, arg);
    let quadruple_arg = mul2_raw(ctx, four, arg);
    let sextuple_arg = mul2_raw(ctx, six, arg);
    let octuple_arg = mul2_raw(ctx, eight, arg);
    let sin_double = ctx.call_builtin(BuiltinFn::Sin, vec![double_arg]);
    let sin_quadruple = ctx.call_builtin(BuiltinFn::Sin, vec![quadruple_arg]);
    let sin_sextuple = ctx.call_builtin(BuiltinFn::Sin, vec![sextuple_arg]);
    let sin_octuple = ctx.call_builtin(BuiltinFn::Sin, vec![octuple_arg]);

    let double_scale = BigRational::new(7.into(), 32.into()) / a.clone();
    let signed_double_scale = match builtin {
        BuiltinFn::Sin => -double_scale,
        BuiltinFn::Cos => double_scale,
        _ => return None,
    };
    let sextuple_scale = BigRational::new(1.into(), 96.into()) / a.clone();
    let signed_sextuple_scale = match builtin {
        BuiltinFn::Sin => -sextuple_scale,
        BuiltinFn::Cos => sextuple_scale,
        _ => return None,
    };

    let double_term = scale_rational_term(ctx, signed_double_scale, sin_double);
    let quadruple_term = scale_rational_term(
        ctx,
        BigRational::new(7.into(), 128.into()) / a.clone(),
        sin_quadruple,
    );
    let sextuple_term = scale_rational_term(ctx, signed_sextuple_scale, sin_sextuple);
    let octuple_term = scale_rational_term(
        ctx,
        BigRational::new(1.into(), 1024.into()) / a,
        sin_octuple,
    );

    let first = ctx.add(Expr::Add(var_term, double_term));
    let second = ctx.add(Expr::Add(first, quadruple_term));
    let third = ctx.add(Expr::Add(second, sextuple_term));
    let primitive = ctx.add(Expr::Add(third, octuple_term));
    Some(cas_ast::hold::wrap_hold(ctx, primitive))
}

fn trig_ratio_power_factor(
    ctx: &Context,
    expr: ExprId,
    builtin: BuiltinFn,
    min_power: i64,
    max_power: i64,
) -> Option<(BigRational, ExprId, i64)> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut powered: Option<(ExprId, i64)> = None;

    for factor in factors {
        match ctx.get(factor).clone() {
            Expr::Pow(base, exp) => {
                let (fn_id, args) = match ctx.get(base).clone() {
                    Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
                    _ => {
                        scale *= rational_constant_value(ctx, factor)?;
                        continue;
                    }
                };
                if ctx.builtin_of(fn_id) != Some(builtin) {
                    scale *= rational_constant_value(ctx, factor)?;
                    continue;
                }

                let power = bounded_positive_integer_power(ctx, exp, min_power, max_power)?;
                if powered.replace((args[0], power)).is_some() {
                    return None;
                }
            }
            Expr::Function(fn_id, args)
                if args.len() == 1 && min_power <= 1 && ctx.builtin_of(fn_id) == Some(builtin) =>
            {
                if powered.replace((args[0], 1)).is_some() {
                    return None;
                }
            }
            _ => scale *= rational_constant_value(ctx, factor)?,
        }
    }

    let (arg, power) = powered?;
    Some((scale, arg, power))
}

fn trig_power_base(
    ctx: &Context,
    expr: ExprId,
    min_power: i64,
    max_power: i64,
) -> Option<(BuiltinFn, ExprId, i64)> {
    let Expr::Pow(base, exp) = ctx.get(expr).clone() else {
        return None;
    };
    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };
    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Sin | BuiltinFn::Cos) {
        return None;
    }
    let power = bounded_positive_integer_power(ctx, exp, min_power, max_power)?;
    Some((builtin, args[0], power))
}

fn trig_ratio_power_reciprocal_square_parts(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
) -> Option<(BigRational, BuiltinFn, ExprId, i64, BigRational)> {
    if let Some((den_builtin, den_arg)) = reciprocal_trig_square_parts(ctx, den) {
        let (num_builtin, primitive_builtin, sign) = match den_builtin {
            BuiltinFn::Cos => (BuiltinFn::Tan, BuiltinFn::Tan, BigRational::one()),
            BuiltinFn::Sin => (BuiltinFn::Cot, BuiltinFn::Cot, -BigRational::one()),
            _ => return None,
        };
        let (scale, num_arg, power) = trig_ratio_power_factor(ctx, num, num_builtin, 1, 5)?;
        if compare_expr(ctx, den_arg, num_arg) != Ordering::Equal {
            return None;
        }
        return Some((scale, primitive_builtin, den_arg, power, sign));
    }

    let (den_builtin, den_arg, den_power) = trig_power_base(ctx, den, 3, 7)?;
    let (num_builtin, primitive_builtin, sign) = match den_builtin {
        BuiltinFn::Cos => (BuiltinFn::Sin, BuiltinFn::Tan, BigRational::one()),
        BuiltinFn::Sin => (BuiltinFn::Cos, BuiltinFn::Cot, -BigRational::one()),
        _ => return None,
    };
    let (scale, num_arg, num_power) = trig_ratio_power_factor(ctx, num, num_builtin, 1, 5)?;
    if den_power != num_power + 2 {
        return None;
    }
    if compare_expr(ctx, den_arg, num_arg) != Ordering::Equal {
        return None;
    }

    Some((scale, primitive_builtin, den_arg, num_power, sign))
}

fn trig_ratio_power_reciprocal_square_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (outer_scale, num, den) = match ctx.get(expr) {
        Expr::Div(num, den) => (BigRational::one(), *num, *den),
        Expr::Mul(l, r) if !contains_named_var(ctx, *l, var) => {
            let Expr::Div(num, den) = ctx.get(*r) else {
                return None;
            };
            (rational_constant_value(ctx, *l)?, *num, *den)
        }
        Expr::Mul(l, r) if !contains_named_var(ctx, *r, var) => {
            let Expr::Div(num, den) = ctx.get(*l) else {
                return None;
            };
            (rational_constant_value(ctx, *r)?, *num, *den)
        }
        _ => return None,
    };
    let (scale, primitive_builtin, arg, power, sign) =
        trig_ratio_power_reciprocal_square_parts(ctx, num, den)?;

    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let base = ctx.call_builtin(primitive_builtin, vec![arg]);
    let next_power = ctx.num(power + 1);
    let primitive = ctx.add(Expr::Pow(base, next_power));
    let denominator = BigRational::from_integer((power + 1).into()) * a;
    let scale = sign * outer_scale * scale / denominator;
    let scale = BigRational::new(scale.numer().clone(), scale.denom().clone());
    Some(scale_reciprocal_integration_result_preserving_presentation(
        ctx, scale, primitive,
    ))
}

fn hyperbolic_power_times_derivative_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let factors = mul_leaves(ctx, expr);
    let mut scale = BigRational::one();
    let mut powered: Option<(BuiltinFn, ExprId, i64)> = None;
    let mut derivative_factor: Option<(BuiltinFn, ExprId)> = None;

    for factor in factors {
        match ctx.get(factor).clone() {
            Expr::Pow(base, exp) => {
                let (fn_id, args) = match ctx.get(base).clone() {
                    Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
                    _ => {
                        scale *= rational_constant_value(ctx, factor)?;
                        continue;
                    }
                };
                let builtin = ctx.builtin_of(fn_id)?;
                if !matches!(builtin, BuiltinFn::Sinh | BuiltinFn::Cosh) {
                    scale *= rational_constant_value(ctx, factor)?;
                    continue;
                }
                let power = bounded_positive_integer_power(ctx, exp, 2, 5)?;
                if powered.replace((builtin, args[0], power)).is_some() {
                    return None;
                }
            }
            Expr::Function(fn_id, args) if args.len() == 1 => match ctx.builtin_of(fn_id) {
                Some(builtin @ (BuiltinFn::Sinh | BuiltinFn::Cosh)) => {
                    if derivative_factor.replace((builtin, args[0])).is_some() {
                        return None;
                    }
                }
                _ => scale *= rational_constant_value(ctx, factor)?,
            },
            _ => scale *= rational_constant_value(ctx, factor)?,
        }
    }

    let (powered_builtin, powered_arg, power) = powered?;
    let (derivative_builtin, derivative_arg) = derivative_factor?;
    if compare_expr(ctx, powered_arg, derivative_arg) != Ordering::Equal {
        return None;
    }

    match (powered_builtin, derivative_builtin) {
        (BuiltinFn::Sinh, BuiltinFn::Cosh) | (BuiltinFn::Cosh, BuiltinFn::Sinh) => {}
        _ => return None,
    }

    let (a, _) = get_linear_coeffs(ctx, powered_arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let base = ctx.call_builtin(powered_builtin, vec![powered_arg]);
    let next_power = ctx.num(power + 1);
    let primitive = ctx.add(Expr::Pow(base, next_power));
    let denominator = BigRational::from_integer((power + 1).into()) * a;
    Some(scale_rational_term(ctx, scale / denominator, primitive))
}

fn bounded_positive_integer_power(ctx: &Context, expr: ExprId, min: i64, max: i64) -> Option<i64> {
    let Expr::Number(value) = ctx.get(expr) else {
        return None;
    };
    if !value.denom().is_one() {
        return None;
    }
    let value = value.to_integer().to_i64()?;
    (min..=max).contains(&value).then_some(value)
}

fn trig_odd_power_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    let power = if is_number(ctx, exp, 3) {
        3
    } else if is_number(ctx, exp, 5) {
        5
    } else if is_number(ctx, exp, 7) {
        7
    } else {
        return None;
    };

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Sin | BuiltinFn::Cos) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let companion_builtin = match builtin {
        BuiltinFn::Sin => BuiltinFn::Cos,
        BuiltinFn::Cos => BuiltinFn::Sin,
        _ => return None,
    };
    let companion = ctx.call_builtin(companion_builtin, vec![arg]);

    let primitive = match power {
        3 => trig_cube_primitive(ctx, builtin, companion)?,
        5 => trig_fifth_primitive(ctx, builtin, companion)?,
        7 => trig_seventh_primitive(ctx, builtin, companion)?,
        _ => return None,
    };

    if a.is_one() {
        Some(primitive)
    } else if power == 7 {
        Some(scale_reciprocal_integration_result_preserving_presentation(
            ctx,
            BigRational::one() / a,
            primitive,
        ))
    } else {
        Some(scale_rational_term(ctx, BigRational::one() / a, primitive))
    }
}

fn trig_cube_primitive(ctx: &mut Context, builtin: BuiltinFn, companion: ExprId) -> Option<ExprId> {
    let three = ctx.num(3);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let cubic_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 3.into()), companion_cubed);

    match builtin {
        BuiltinFn::Sin => {
            let neg_companion = ctx.add(Expr::Neg(companion));
            Some(ctx.add(Expr::Add(neg_companion, cubic_term)))
        }
        BuiltinFn::Cos => Some(ctx.add(Expr::Sub(companion, cubic_term))),
        _ => None,
    }
}

fn trig_fifth_primitive(
    ctx: &mut Context,
    builtin: BuiltinFn,
    companion: ExprId,
) -> Option<ExprId> {
    let three = ctx.num(3);
    let five = ctx.num(5);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let companion_fifth = ctx.add(Expr::Pow(companion, five));

    let cubic_term =
        scale_rational_term(ctx, BigRational::new(2.into(), 3.into()), companion_cubed);
    let fifth_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 5.into()), companion_fifth);

    match builtin {
        BuiltinFn::Sin => {
            let neg_companion = ctx.add(Expr::Neg(companion));
            let neg_fifth = ctx.add(Expr::Neg(fifth_term));
            let first_two = ctx.add(Expr::Add(neg_companion, cubic_term));
            Some(ctx.add(Expr::Add(first_two, neg_fifth)))
        }
        BuiltinFn::Cos => {
            let neg_cubic = ctx.add(Expr::Neg(cubic_term));
            let first_two = ctx.add(Expr::Add(companion, neg_cubic));
            Some(ctx.add(Expr::Add(first_two, fifth_term)))
        }
        _ => None,
    }
}

fn trig_seventh_primitive(
    ctx: &mut Context,
    builtin: BuiltinFn,
    companion: ExprId,
) -> Option<ExprId> {
    let three = ctx.num(3);
    let five = ctx.num(5);
    let seven = ctx.num(7);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let companion_fifth = ctx.add(Expr::Pow(companion, five));
    let companion_seventh = ctx.add(Expr::Pow(companion, seven));

    let fifth_term =
        scale_rational_term(ctx, BigRational::new(3.into(), 5.into()), companion_fifth);
    let seventh_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 7.into()), companion_seventh);

    match builtin {
        BuiltinFn::Sin => {
            let neg_companion = ctx.add(Expr::Neg(companion));
            let neg_fifth = ctx.add(Expr::Neg(fifth_term));
            let first_two = ctx.add(Expr::Add(neg_companion, companion_cubed));
            let first_three = ctx.add(Expr::Add(first_two, neg_fifth));
            Some(ctx.add(Expr::Add(first_three, seventh_term)))
        }
        BuiltinFn::Cos => {
            let neg_cubed = ctx.add(Expr::Neg(companion_cubed));
            let neg_seventh = ctx.add(Expr::Neg(seventh_term));
            let first_two = ctx.add(Expr::Add(companion, neg_cubed));
            let first_three = ctx.add(Expr::Add(first_two, fifth_term));
            Some(ctx.add(Expr::Add(first_three, neg_seventh)))
        }
        _ => None,
    }
}

fn hyperbolic_odd_power_limited_affine_antiderivative(
    ctx: &mut Context,
    base: ExprId,
    exp: ExprId,
    var: &str,
) -> Option<ExprId> {
    let power = if is_number(ctx, exp, 3) {
        3
    } else if is_number(ctx, exp, 5) {
        5
    } else if is_number(ctx, exp, 7) {
        7
    } else {
        return None;
    };

    let (fn_id, args) = match ctx.get(base).clone() {
        Expr::Function(fn_id, args) if args.len() == 1 => (fn_id, args),
        _ => return None,
    };

    let builtin = ctx.builtin_of(fn_id)?;
    if !matches!(builtin, BuiltinFn::Sinh | BuiltinFn::Cosh) {
        return None;
    }

    let arg = args[0];
    let (a, _) = get_linear_coeffs(ctx, arg, var)?;
    let a = rational_constant_value(ctx, a)?;
    if a.is_zero() {
        return None;
    }

    let companion_builtin = match builtin {
        BuiltinFn::Sinh => BuiltinFn::Cosh,
        BuiltinFn::Cosh => BuiltinFn::Sinh,
        _ => return None,
    };
    let companion = ctx.call_builtin(companion_builtin, vec![arg]);

    let primitive = match power {
        3 => hyperbolic_cube_primitive(ctx, builtin, companion)?,
        5 => hyperbolic_fifth_primitive(ctx, builtin, companion)?,
        7 => hyperbolic_seventh_primitive(ctx, builtin, companion)?,
        _ => return None,
    };

    if a.is_one() {
        Some(primitive)
    } else {
        Some(scale_rational_term(ctx, BigRational::one() / a, primitive))
    }
}

fn hyperbolic_cube_primitive(
    ctx: &mut Context,
    builtin: BuiltinFn,
    companion: ExprId,
) -> Option<ExprId> {
    let three = ctx.num(3);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let cubic_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 3.into()), companion_cubed);

    match builtin {
        BuiltinFn::Sinh => Some(ctx.add(Expr::Sub(cubic_term, companion))),
        BuiltinFn::Cosh => Some(ctx.add(Expr::Add(companion, cubic_term))),
        _ => None,
    }
}

fn hyperbolic_fifth_primitive(
    ctx: &mut Context,
    builtin: BuiltinFn,
    companion: ExprId,
) -> Option<ExprId> {
    let three = ctx.num(3);
    let five = ctx.num(5);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let companion_fifth = ctx.add(Expr::Pow(companion, five));

    let cubic_term =
        scale_rational_term(ctx, BigRational::new(2.into(), 3.into()), companion_cubed);
    let fifth_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 5.into()), companion_fifth);

    match builtin {
        BuiltinFn::Sinh => {
            let first_two = ctx.add(Expr::Sub(fifth_term, cubic_term));
            Some(ctx.add(Expr::Add(first_two, companion)))
        }
        BuiltinFn::Cosh => {
            let first_two = ctx.add(Expr::Add(companion, cubic_term));
            Some(ctx.add(Expr::Add(first_two, fifth_term)))
        }
        _ => None,
    }
}

fn hyperbolic_seventh_primitive(
    ctx: &mut Context,
    builtin: BuiltinFn,
    companion: ExprId,
) -> Option<ExprId> {
    let three = ctx.num(3);
    let five = ctx.num(5);
    let seven = ctx.num(7);
    let companion_cubed = ctx.add(Expr::Pow(companion, three));
    let companion_fifth = ctx.add(Expr::Pow(companion, five));
    let companion_seventh = ctx.add(Expr::Pow(companion, seven));

    let fifth_term =
        scale_rational_term(ctx, BigRational::new(3.into(), 5.into()), companion_fifth);
    let seventh_term =
        scale_rational_term(ctx, BigRational::new(1.into(), 7.into()), companion_seventh);

    match builtin {
        BuiltinFn::Sinh => {
            let without_linear = ctx.add(Expr::Sub(companion_cubed, companion));
            let first_three = ctx.add(Expr::Sub(without_linear, fifth_term));
            Some(ctx.add(Expr::Add(first_three, seventh_term)))
        }
        BuiltinFn::Cosh => {
            let first_two = ctx.add(Expr::Add(companion, companion_cubed));
            let first_three = ctx.add(Expr::Add(first_two, fifth_term));
            Some(ctx.add(Expr::Add(first_three, seventh_term)))
        }
        _ => None,
    }
}

fn polynomial_reciprocal_trig_square_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (builtin, arg) = reciprocal_trig_square_parts(ctx, den)?;
    let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
    let arg_poly = Polynomial::from_expr(ctx, arg, var).ok()?;
    let derivative = arg_poly.derivative();
    let scale = constant_polynomial_ratio(&numerator, &derivative)?;
    if scale.is_zero() {
        return None;
    }

    let integral = match builtin {
        BuiltinFn::Cos => ctx.call_builtin(BuiltinFn::Tan, vec![arg]),
        BuiltinFn::Sin => {
            let cot_arg = ctx.call_builtin(BuiltinFn::Cot, vec![arg]);
            ctx.add(Expr::Neg(cot_arg))
        }
        _ => return None,
    };

    if matches!(builtin, BuiltinFn::Cos | BuiltinFn::Sin) {
        Some(scale_reciprocal_integration_result_preserving_presentation(
            ctx, scale, integral,
        ))
    } else {
        Some(scale_reciprocal_integration_result(ctx, scale, integral))
    }
}

fn hyperbolic_reciprocal_power_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
    denominator_builtin: BuiltinFn,
    power: i64,
) -> Option<ExprId> {
    let policy = hyperbolic_reciprocal_table_policy(denominator_builtin, power)?;
    let arg = reciprocal_hyperbolic_power_arg(
        ctx,
        den,
        policy.denominator_builtin,
        policy.power.exponent(),
    )?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let scale = symbolic_linear_cofactor_scale_expr(ctx, num, arg, var)?;
    if is_number(ctx, scale, 0) {
        return None;
    }

    Some(build_hyperbolic_reciprocal_table_integral(
        ctx,
        policy,
        arg,
        scale,
        hyperbolic_reciprocal_primitive_scale_ops(),
    ))
}

fn hyperbolic_reciprocal_primitive_scale_ops() -> HyperbolicReciprocalPrimitiveScaleOps {
    HyperbolicReciprocalPrimitiveScaleOps::new(
        scale_rational_term,
        rational_over_expr,
        scale_expr_reciprocal_integration_result,
        negate_scalar_expr,
    )
}

fn hyperbolic_log_derivative_ratio_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (den, scale) = hyperbolic_log_derivative_ratio_parts(ctx, num, den, var)?;
    Some(hyperbolic_log_derivative_ratio_antiderivative_from_parts(
        ctx, den, scale,
    ))
}

fn hyperbolic_log_derivative_ratio_parts(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<(ExprId, ExprId)> {
    let (den_builtin, arg) = match ctx.get(den) {
        Expr::Function(fn_id, args) if args.len() == 1 => (ctx.builtin_of(*fn_id)?, args[0]),
        _ => return None,
    };
    let numerator_builtin = match den_builtin {
        BuiltinFn::Cosh => BuiltinFn::Sinh,
        BuiltinFn::Sinh => BuiltinFn::Cosh,
        _ => return None,
    };
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let cofactor = product_cofactor_excluding_unary_builtin_arg(
        ctx,
        num,
        numerator_builtin,
        |ctx, numerator_arg| compare_expr(ctx, numerator_arg, arg) == Ordering::Equal,
    )?;

    let scale = symbolic_linear_cofactor_scale_expr(ctx, cofactor, arg, var)?;

    Some((den, scale))
}

fn hyperbolic_log_derivative_ratio_antiderivative_from_parts(
    ctx: &mut Context,
    den: ExprId,
    scale: ExprId,
) -> ExprId {
    let log_arg = cas_ast::hold::wrap_hold(ctx, den);
    let log_abs = ln_abs(ctx, log_arg);
    scale_expr_reciprocal_integration_result(ctx, scale, log_abs)
}

fn hyperbolic_tanh_log_cosh_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (arg, scale) = hyperbolic_tanh_log_cosh_parts(ctx, expr, var)?;
    let cosh_arg = ctx.call_builtin(BuiltinFn::Cosh, vec![arg]);
    let log_abs = ln_abs(ctx, cosh_arg);
    Some(scale_expr_reciprocal_integration_result(
        ctx, scale, log_abs,
    ))
}

fn hyperbolic_tanh_log_cosh_parts(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<(ExprId, ExprId)> {
    let factors = mul_leaves(ctx, expr);
    let (tanh_index, arg) = indexed_hyperbolic_tangent_factor_arg(ctx, &factors)?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let cofactor = factor_product_excluding_index(ctx, &factors, tanh_index);
    let scale = symbolic_linear_cofactor_scale_expr(ctx, cofactor, arg, var)?;
    if is_number(ctx, scale, 0) {
        return None;
    }

    Some((arg, scale))
}

fn trig_log_derivative_ratio_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (_, _, scaled) = trig_log_derivative_ratio_scale(ctx, num, den, var)?;
    let log_arg = cas_ast::hold::wrap_hold(ctx, den);
    let log_abs = ln_abs(ctx, log_arg);
    Some(scale_expr_reciprocal_integration_result(
        ctx, scaled, log_abs,
    ))
}

fn trig_log_derivative_ratio_scale(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<(BuiltinFn, ExprId, ExprId)> {
    let (den_builtin, arg) = match ctx.get(den) {
        Expr::Function(fn_id, args) if args.len() == 1 => (ctx.builtin_of(*fn_id)?, args[0]),
        _ => return None,
    };
    let numerator_builtin = trig_log_derivative_numerator_builtin(den_builtin)?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let cofactor = trig_log_derivative_ratio_cofactor(ctx, num, numerator_builtin, arg)?;
    let scale = symbolic_linear_cofactor_scale_expr(ctx, cofactor, arg, var)?;

    let scaled = match den_builtin {
        BuiltinFn::Cos => negate_scalar_expr(ctx, scale),
        BuiltinFn::Sin => scale,
        _ => return None,
    };
    Some((den_builtin, arg, scaled))
}

fn trig_log_derivative_ratio_cofactor(
    ctx: &mut Context,
    num: ExprId,
    numerator_builtin: BuiltinFn,
    arg: ExprId,
) -> Option<ExprId> {
    additive_cofactor_from_term_cofactors(ctx, num, |ctx, term| {
        trig_log_derivative_ratio_term_cofactor(ctx, term, numerator_builtin, arg)
    })
}

fn trig_log_derivative_ratio_term_cofactor(
    ctx: &mut Context,
    term: ExprId,
    numerator_builtin: BuiltinFn,
    arg: ExprId,
) -> Option<ExprId> {
    product_cofactor_excluding_unary_builtin_arg(
        ctx,
        term,
        numerator_builtin,
        |ctx, numerator_arg| compare_expr(ctx, numerator_arg, arg) == Ordering::Equal,
    )
}

fn trig_log_derivative_ratio_required_nonzero(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (num, den) = match ctx.get(expr).clone() {
        Expr::Div(num, den) => (num, den),
        _ => return None,
    };
    let (den_builtin, arg, _) = trig_log_derivative_ratio_scale(ctx, num, den, var)?;
    build_reciprocal_trig_denominator_nonzero_condition(ctx, den_builtin, arg)
}

fn nested_trig_log_derivative_log_factor(
    ctx: &Context,
    expr: ExprId,
) -> Option<(BuiltinFn, ExprId, ExprId)> {
    let Expr::Function(fn_id, args) = ctx.get(expr) else {
        return None;
    };
    if args.len() != 1 || ctx.builtin_of(*fn_id) != Some(BuiltinFn::Ln) {
        return None;
    }

    let log_arg = args[0];
    match ctx.get(log_arg) {
        Expr::Function(inner_fn_id, inner_args) if inner_args.len() == 1 => {
            let builtin = ctx.builtin_of(*inner_fn_id)?;
            match builtin {
                BuiltinFn::Tan | BuiltinFn::Cot => Some((builtin, inner_args[0], expr)),
                _ => None,
            }
        }
        Expr::Div(num, den) => {
            if let (Some(sin_arg), Some(cos_arg)) = (
                unary_builtin_arg(ctx, *num, BuiltinFn::Sin),
                unary_builtin_arg(ctx, *den, BuiltinFn::Cos),
            ) {
                if compare_expr(ctx, sin_arg, cos_arg) == Ordering::Equal {
                    return Some((BuiltinFn::Tan, sin_arg, expr));
                }
            }

            if let (Some(cos_arg), Some(sin_arg)) = (
                unary_builtin_arg(ctx, *num, BuiltinFn::Cos),
                unary_builtin_arg(ctx, *den, BuiltinFn::Sin),
            ) {
                if compare_expr(ctx, cos_arg, sin_arg) == Ordering::Equal {
                    return Some((BuiltinFn::Cot, cos_arg, expr));
                }
            }

            None
        }
        _ => None,
    }
}

fn indexed_nested_trig_log_derivative_log_factor(
    ctx: &Context,
    factors: &[ExprId],
) -> Option<(usize, BuiltinFn, ExprId, ExprId)> {
    factors.iter().enumerate().find_map(|(idx, factor)| {
        nested_trig_log_derivative_log_factor(ctx, *factor)
            .map(|(builtin, arg, log_arg)| (idx, builtin, arg, log_arg))
    })
}

fn indexed_matching_unary_builtin_factor(
    ctx: &Context,
    factors: &[ExprId],
    builtin: BuiltinFn,
    arg: ExprId,
    excluded: &[usize],
) -> Option<usize> {
    factors.iter().enumerate().find_map(|(idx, factor)| {
        if excluded.contains(&idx) {
            return None;
        }
        let factor_arg = unary_builtin_arg(ctx, *factor, builtin)?;
        (compare_expr(ctx, factor_arg, arg) == Ordering::Equal).then_some(idx)
    })
}

fn nested_trig_log_derivative_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let numerator_factors = mul_leaves(ctx, num);
    let denominator_factors = mul_leaves(ctx, den);
    let (log_index, log_builtin, arg, log_arg) =
        indexed_nested_trig_log_derivative_log_factor(ctx, &denominator_factors)?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let sin_index = indexed_matching_unary_builtin_factor(
        ctx,
        &denominator_factors,
        BuiltinFn::Sin,
        arg,
        &[log_index],
    )?;
    let cos_index = indexed_matching_unary_builtin_factor(
        ctx,
        &denominator_factors,
        BuiltinFn::Cos,
        arg,
        &[log_index, sin_index],
    )?;

    let remaining_denominator: Vec<_> = denominator_factors
        .iter()
        .enumerate()
        .filter_map(|(idx, factor)| {
            (![log_index, sin_index, cos_index].contains(&idx)).then_some(*factor)
        })
        .collect();

    let arg_poly = Polynomial::from_expr(ctx, arg, var).ok()?;
    let derivative = arg_poly.derivative();
    let mut scale = quotient_scale_against_polynomial(
        ctx,
        &numerator_factors,
        &remaining_denominator,
        &derivative,
        var,
    )?;
    if scale.is_zero() {
        return None;
    }
    if log_builtin == BuiltinFn::Cot {
        scale = -scale;
    }

    let log_abs = ln_abs(ctx, log_arg);
    Some(scale_rational_term(ctx, scale, log_abs))
}

fn hyperbolic_tanh_reciprocal_log_sinh_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (arg, scale) = hyperbolic_tanh_reciprocal_log_sinh_parts(ctx, num, den, var)?;
    Some(hyperbolic_tanh_reciprocal_log_sinh_antiderivative_from_parts(ctx, arg, scale))
}

fn hyperbolic_tanh_reciprocal_log_sinh_parts(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<(ExprId, ExprId)> {
    let arg = hyperbolic_tangent_arg(ctx, den)?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let scale = symbolic_linear_cofactor_scale_expr(ctx, num, arg, var)?;
    if is_number(ctx, scale, 0) {
        return None;
    }

    Some((arg, scale))
}

fn hyperbolic_tanh_reciprocal_log_sinh_antiderivative_from_parts(
    ctx: &mut Context,
    arg: ExprId,
    scale: ExprId,
) -> ExprId {
    let sinh_arg = ctx.call_builtin(BuiltinFn::Sinh, vec![arg]);
    let log_abs = ln_abs(ctx, sinh_arg);
    scale_expr_reciprocal_integration_result(ctx, scale, log_abs)
}

fn hyperbolic_reciprocal_derivative_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    let parts = hyperbolic_reciprocal_derivative_parts(ctx, num, den, var)?;
    hyperbolic_reciprocal_derivative_antiderivative_from_parts(ctx, parts)
}

struct HyperbolicReciprocalDerivativeParts {
    denominator_builtin: BuiltinFn,
    arg: ExprId,
    scale: ExprId,
}

fn hyperbolic_reciprocal_derivative_parts(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<HyperbolicReciprocalDerivativeParts> {
    let (den_builtin, arg) = reciprocal_hyperbolic_square_parts(ctx, den)?;
    let policy = hyperbolic_reciprocal_derivative_policy(den_builtin)?;
    if !contains_named_var(ctx, arg, var) {
        return None;
    }

    let cofactor = product_cofactor_excluding_unary_builtin_arg(
        ctx,
        num,
        policy.numerator_builtin,
        |ctx, numerator_arg| same_structural_or_linear_arg(ctx, numerator_arg, arg, var),
    )?;

    let scale = symbolic_linear_cofactor_scale_expr(ctx, cofactor, arg, var)?;
    if is_number(ctx, scale, 0) {
        return None;
    }

    Some(HyperbolicReciprocalDerivativeParts {
        denominator_builtin: den_builtin,
        arg,
        scale,
    })
}

fn hyperbolic_reciprocal_derivative_antiderivative_from_parts(
    ctx: &mut Context,
    parts: HyperbolicReciprocalDerivativeParts,
) -> Option<ExprId> {
    let policy = hyperbolic_reciprocal_derivative_policy(parts.denominator_builtin)?;
    let integral = build_hyperbolic_reciprocal_derivative_integral(ctx, policy, parts.arg);
    Some(scale_expr_reciprocal_integration_result(
        ctx,
        parts.scale,
        integral,
    ))
}

fn hyperbolic_reciprocal_square_antiderivative(
    ctx: &mut Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<ExprId> {
    hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Cosh, 1)
        .or_else(|| {
            hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Sinh, 1)
        })
        .or_else(|| {
            hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Cosh, 2)
        })
        .or_else(|| {
            hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Cosh, 4)
        })
        .or_else(|| {
            hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Sinh, 2)
        })
        .or_else(|| {
            hyperbolic_reciprocal_power_antiderivative(ctx, num, den, var, BuiltinFn::Sinh, 4)
        })
        .or_else(|| hyperbolic_reciprocal_derivative_antiderivative(ctx, num, den, var))
}

pub fn integrate_symbolic_is_hyperbolic_quotient_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            hyperbolic_log_derivative_ratio_antiderivative(ctx, num, den, var).is_some()
                || hyperbolic_tanh_reciprocal_log_sinh_antiderivative(ctx, num, den, var).is_some()
                || hyperbolic_reciprocal_square_antiderivative(ctx, num, den, var).is_some()
        }
        Expr::Mul(left, right) => {
            (!contains_named_var(ctx, left, var)
                && integrate_symbolic_is_hyperbolic_quotient_substitution_target(ctx, right, var))
                || (!contains_named_var(ctx, right, var)
                    && integrate_symbolic_is_hyperbolic_quotient_substitution_target(
                        ctx, left, var,
                    ))
        }
        Expr::Neg(inner) => {
            integrate_symbolic_is_hyperbolic_quotient_substitution_target(ctx, inner, var)
        }
        _ => false,
    }
}

pub fn integrate_symbolic_is_trig_quotient_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            trig_log_derivative_ratio_antiderivative(ctx, num, den, var).is_some()
                || nested_trig_log_derivative_antiderivative(ctx, num, den, var).is_some()
                || polynomial_reciprocal_trig_square_antiderivative(ctx, num, den, var).is_some()
                || polynomial_trig_reciprocal_derivative_antiderivative(ctx, num, den, var)
                    .is_some()
                || polynomial_trig_reciprocal_factor_antiderivative(ctx, num, den, var).is_some()
                || trig_tan_fourth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_cot_fourth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_tan_sixth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_cot_sixth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_tan_eighth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_cot_eighth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_sec_sixth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_csc_sixth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_sec_eighth_quotient_antiderivative(ctx, num, den, var).is_some()
                || trig_csc_eighth_quotient_antiderivative(ctx, num, den, var).is_some()
        }
        Expr::Mul(left, right) => {
            (!contains_named_var(ctx, left, var)
                && integrate_symbolic_is_trig_quotient_substitution_target(ctx, right, var))
                || (!contains_named_var(ctx, right, var)
                    && integrate_symbolic_is_trig_quotient_substitution_target(ctx, left, var))
        }
        Expr::Neg(inner) => {
            integrate_symbolic_is_trig_quotient_substitution_target(ctx, inner, var)
        }
        _ => false,
    }
}

