fn arcsin_polynomial_substitution_radicand(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            if let Some(radicand) = sqrt_like_radicand(ctx, den) {
                arcsin_polynomial_substitution_from_radicand(ctx, num, radicand, var)?;
                return Some(radicand);
            }

            let denominator = Polynomial::from_expr(ctx, den, var).ok()?;
            let factors = mul_leaves(ctx, num);
            let (sqrt_index, radicand) = factors.iter().enumerate().find_map(|(idx, factor)| {
                let radicand = sqrt_like_radicand(ctx, *factor)?;
                let radicand_poly = Polynomial::from_expr(ctx, radicand, var).ok()?;
                (radicand_poly == denominator).then_some((idx, radicand))
            })?;

            let cofactor_factors: Vec<ExprId> = factors
                .iter()
                .enumerate()
                .filter_map(|(idx, factor)| (idx != sqrt_index).then_some(*factor))
                .collect();
            let cofactor = if cofactor_factors.is_empty() {
                ctx.num(1)
            } else {
                build_balanced_mul(ctx, &cofactor_factors)
            };
            arcsin_polynomial_substitution_from_radicand(ctx, cofactor, radicand, var)?;
            Some(radicand)
        }
        Expr::Mul(_, _) => {
            let factors = mul_leaves(ctx, expr);
            let (sqrt_index, radicand) = factors.iter().enumerate().find_map(|(idx, factor)| {
                reciprocal_sqrt_like_radicand(ctx, *factor).map(|radicand| (idx, radicand))
            })?;

            let cofactor_factors: Vec<ExprId> = factors
                .iter()
                .enumerate()
                .filter_map(|(idx, factor)| (idx != sqrt_index).then_some(*factor))
                .collect();
            let cofactor = if cofactor_factors.is_empty() {
                ctx.num(1)
            } else {
                build_balanced_mul(ctx, &cofactor_factors)
            };
            arcsin_polynomial_substitution_from_radicand(ctx, cofactor, radicand, var)?;
            Some(radicand)
        }
        _ => None,
    }
}

fn arcsin_inverse_sqrt_product_substitution_radicand(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let expr = cas_ast::hold::strip_all_holds(ctx, expr);

    if let Some(radicand) = reciprocal_sqrt_like_radicand(ctx, expr) {
        if mul_leaves(ctx, radicand).len() >= 2 {
            let one = ctx.num(1);
            arcsin_polynomial_substitution_from_radicand(ctx, one, radicand, var)?;
            return Some(radicand);
        }
    }

    let mut numerator_factors = Vec::new();
    let mut denominator_factors = Vec::new();
    collect_fraction_factors_for_inverse_sqrt_product(
        ctx,
        expr,
        false,
        &mut numerator_factors,
        &mut denominator_factors,
    );

    let mut radicands = Vec::new();
    let mut remaining_denominator_factors = Vec::new();
    for factor in denominator_factors {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            radicands.push(radicand);
        } else {
            remaining_denominator_factors.push(factor);
        }
    }
    if radicands.len() < 2 {
        return None;
    }

    let numerator = if numerator_factors.is_empty() {
        ctx.num(1)
    } else {
        build_balanced_mul(ctx, &numerator_factors)
    };
    let cofactor = if remaining_denominator_factors.is_empty() {
        numerator
    } else {
        let denominator = build_balanced_mul(ctx, &remaining_denominator_factors);
        ctx.add(Expr::Div(numerator, denominator))
    };

    let combined_radicand = build_balanced_mul(ctx, &radicands);
    let validation_cofactor =
        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, cofactor, var);
    arcsin_polynomial_substitution_from_radicand(ctx, validation_cofactor, combined_radicand, var)?;
    Some(combined_radicand)
}

fn is_sqrt_of_var(ctx: &Context, expr: ExprId, var: &str) -> bool {
    sqrt_like_radicand(ctx, expr).is_some_and(|radicand| is_var(ctx, radicand, var))
}

fn is_neg_var(ctx: &Context, expr: ExprId, var: &str) -> bool {
    matches!(ctx.get(expr), Expr::Neg(inner) if is_var(ctx, *inner, var))
}

fn is_sqrt_var_minus_var(ctx: &Context, expr: ExprId, var: &str) -> bool {
    match ctx.get(expr) {
        Expr::Sub(left, right) => is_sqrt_of_var(ctx, *left, var) && is_var(ctx, *right, var),
        Expr::Add(left, right) => {
            (is_sqrt_of_var(ctx, *left, var) && is_neg_var(ctx, *right, var))
                || (is_neg_var(ctx, *left, var) && is_sqrt_of_var(ctx, *right, var))
        }
        _ => false,
    }
}

fn is_var_times_sqrt_var_minus_var_radicand(ctx: &Context, radicand: ExprId, var: &str) -> bool {
    let factors = mul_leaves(ctx, radicand);
    match factors.as_slice() {
        [left, right] => {
            (is_var(ctx, *left, var) && is_sqrt_var_minus_var(ctx, *right, var))
                || (is_sqrt_var_minus_var(ctx, *left, var) && is_var(ctx, *right, var))
        }
        _ => false,
    }
}

fn shifted_sqrt_arcsin_inverse_product_cofactor(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let expr = cas_ast::hold::strip_all_holds(ctx, expr);

    if let Some(radicand) = reciprocal_sqrt_like_radicand(ctx, expr) {
        if is_var_times_sqrt_var_minus_var_radicand(ctx, radicand, var) {
            return Some(ctx.num(1));
        }
    }

    let mut numerator_factors = Vec::new();
    let mut denominator_factors = Vec::new();
    collect_fraction_factors_for_inverse_sqrt_product(
        ctx,
        expr,
        false,
        &mut numerator_factors,
        &mut denominator_factors,
    );

    let mut radicands = Vec::new();
    let mut remaining_denominator_factors = Vec::new();
    for factor in denominator_factors {
        if let Some(radicand) = sqrt_like_radicand(ctx, factor) {
            radicands.push(radicand);
        } else {
            remaining_denominator_factors.push(factor);
        }
    }
    if radicands.len() != 2 {
        return None;
    }

    let combined_radicand = build_balanced_mul(ctx, &radicands);
    if !is_var_times_sqrt_var_minus_var_radicand(ctx, combined_radicand, var) {
        return None;
    }

    let numerator = if numerator_factors.is_empty() {
        ctx.num(1)
    } else {
        build_balanced_mul(ctx, &numerator_factors)
    };
    let cofactor = if remaining_denominator_factors.is_empty() {
        numerator
    } else {
        let denominator = build_balanced_mul(ctx, &remaining_denominator_factors);
        ctx.add(Expr::Div(numerator, denominator))
    };
    (!contains_named_var(ctx, cofactor, var)).then_some(cofactor)
}

fn shifted_sqrt_arcsin_inverse_product_antiderivative(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let cofactor = shifted_sqrt_arcsin_inverse_product_cofactor(ctx, expr, var)?;
    let var_expr = ctx.var(var);
    let sqrt_var = ctx.call_builtin(BuiltinFn::Sqrt, vec![var_expr]);
    let two = ctx.num(2);
    let one = ctx.num(1);
    let shifted_sqrt = mul2_raw(ctx, two, sqrt_var);
    let arg = ctx.add(Expr::Sub(shifted_sqrt, one));
    let arcsin = ctx.call_builtin(BuiltinFn::Arcsin, vec![arg]);
    if let Some(scale) = rational_constant_value(ctx, cofactor) {
        return Some(scale_rational_term(
            ctx,
            scale * BigRational::from_integer(2.into()),
            arcsin,
        ));
    }

    let two = ctx.num(2);
    let doubled_cofactor = mul2_raw(ctx, two, cofactor);
    Some(mul2_raw(ctx, doubled_cofactor, arcsin))
}

fn shifted_sqrt_arcsin_inverse_product_positive_conditions(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Vec<ExprId> {
    if shifted_sqrt_arcsin_inverse_product_cofactor(ctx, expr, var).is_none() {
        return vec![];
    }

    let var_expr = ctx.var(var);
    let sqrt_var = ctx.call_builtin(BuiltinFn::Sqrt, vec![var_expr]);
    let var_expr = ctx.var(var);
    vec![var_expr, ctx.add(Expr::Sub(sqrt_var, var_expr))]
}

fn strip_variable_free_factors_from_arcsin_product_cofactor(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> ExprId {
    let expr = cas_ast::hold::strip_all_holds(ctx, expr);
    if !contains_named_var(ctx, expr, var) {
        return ctx.num(1);
    }

    match ctx.get(expr).clone() {
        Expr::Neg(inner) => {
            strip_variable_free_factors_from_arcsin_product_cofactor(ctx, inner, var)
        }
        Expr::Mul(left, right) => {
            let left_depends = contains_named_var(ctx, left, var);
            let right_depends = contains_named_var(ctx, right, var);
            match (left_depends, right_depends) {
                (false, false) => ctx.num(1),
                (false, true) => {
                    strip_variable_free_factors_from_arcsin_product_cofactor(ctx, right, var)
                }
                (true, false) => {
                    strip_variable_free_factors_from_arcsin_product_cofactor(ctx, left, var)
                }
                (true, true) => {
                    let left =
                        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, left, var);
                    let right =
                        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, right, var);
                    mul2_raw(ctx, left, right)
                }
            }
        }
        Expr::Div(num, den) => {
            let num_depends = contains_named_var(ctx, num, var);
            let den_depends = contains_named_var(ctx, den, var);
            match (num_depends, den_depends) {
                (false, false) => ctx.num(1),
                (false, true) => {
                    let one = ctx.num(1);
                    let den =
                        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, den, var);
                    ctx.add(Expr::Div(one, den))
                }
                (true, false) => {
                    strip_variable_free_factors_from_arcsin_product_cofactor(ctx, num, var)
                }
                (true, true) => {
                    let num =
                        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, num, var);
                    let den =
                        strip_variable_free_factors_from_arcsin_product_cofactor(ctx, den, var);
                    ctx.add(Expr::Div(num, den))
                }
            }
        }
        _ => expr,
    }
}

fn collect_fraction_factors_for_inverse_sqrt_product(
    ctx: &Context,
    expr: ExprId,
    in_denominator: bool,
    numerator_factors: &mut Vec<ExprId>,
    denominator_factors: &mut Vec<ExprId>,
) {
    match ctx.get(expr) {
        Expr::Mul(left, right) => {
            collect_fraction_factors_for_inverse_sqrt_product(
                ctx,
                *left,
                in_denominator,
                numerator_factors,
                denominator_factors,
            );
            collect_fraction_factors_for_inverse_sqrt_product(
                ctx,
                *right,
                in_denominator,
                numerator_factors,
                denominator_factors,
            );
        }
        Expr::Div(left, right) => {
            collect_fraction_factors_for_inverse_sqrt_product(
                ctx,
                *left,
                in_denominator,
                numerator_factors,
                denominator_factors,
            );
            collect_fraction_factors_for_inverse_sqrt_product(
                ctx,
                *right,
                !in_denominator,
                numerator_factors,
                denominator_factors,
            );
        }
        _ if in_denominator => denominator_factors.push(expr),
        _ => numerator_factors.push(expr),
    }
}

pub fn integrate_symbolic_is_arcsin_inverse_sqrt_product_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    arcsin_inverse_sqrt_product_substitution_radicand(ctx, expr, var).is_some()
        || shifted_sqrt_arcsin_inverse_product_cofactor(ctx, expr, var).is_some()
}

pub fn integrate_symbolic_is_acosh_polynomial_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    if let Some(inner) = constant_scaled_integrand_inner(ctx, expr, var) {
        return integrate_symbolic_is_acosh_polynomial_substitution_target(ctx, inner, var);
    }

    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            acosh_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
        }
        Expr::Mul(_, _) => {
            acosh_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some()
        }
        _ => false,
    }
}

pub fn integrate_symbolic_is_asinh_polynomial_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            asinh_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
        }
        _ => asinh_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some(),
    }
}

pub fn integrate_symbolic_is_arcsin_polynomial_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            arcsin_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
        }
        _ => arcsin_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some(),
    }
}

fn acosh_polynomial_substitution_positive_conditions(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Vec<ExprId> {
    let Some((radicand, arg_poly, offset_square)) =
        acosh_polynomial_substitution_oriented_radicand_arg(ctx, expr, var)
    else {
        return vec![];
    };

    let Some(offset_expr) = positive_rational_sqrt_expr(ctx, &offset_square) else {
        return vec![radicand];
    };

    let arg = arg_poly.to_expr(ctx);
    let lower_domain = ctx.add(Expr::Sub(arg, offset_expr));
    vec![radicand, lower_domain]
}

fn acosh_polynomial_substitution_oriented_radicand_arg(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<(ExprId, Polynomial, BigRational)> {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            if let Some(radicand) = sqrt_like_radicand(ctx, den) {
                let (radicand, _) =
                    split_positive_rational_content_from_sqrt_radicand(ctx, radicand, var)?;
                let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
                let domain_sample = explicit_sqrt_linear_domain_sample(ctx, den, var);
                let (arg, offset, _) = acosh_polynomial_substitution_oriented_arg(
                    ctx,
                    &numerator,
                    radicand,
                    var,
                    domain_sample.as_ref(),
                )?;
                return Some((radicand, arg, offset));
            }
            if let Some((radicand, _denominator_scale)) =
                sqrt_product_denominator_radicand(ctx, den, var)
            {
                let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
                let domain_sample = explicit_sqrt_linear_domain_sample(ctx, den, var);
                let (arg, offset, _) = acosh_polynomial_substitution_oriented_arg(
                    ctx,
                    &numerator,
                    radicand,
                    var,
                    domain_sample.as_ref(),
                )?;
                return Some((radicand, arg, offset));
            }

            let denominator = Polynomial::from_expr(ctx, den, var).ok()?;
            let factors = mul_leaves(ctx, num);
            let (sqrt_index, radicand) = factors.iter().enumerate().find_map(|(idx, factor)| {
                let radicand = sqrt_like_radicand(ctx, *factor)?;
                let radicand_poly = Polynomial::from_expr(ctx, radicand, var).ok()?;
                (radicand_poly == denominator).then_some((idx, radicand))
            })?;

            let cofactor_factors: Vec<ExprId> = factors
                .iter()
                .enumerate()
                .filter_map(|(idx, factor)| (idx != sqrt_index).then_some(*factor))
                .collect();
            let cofactor = if cofactor_factors.is_empty() {
                ctx.num(1)
            } else {
                build_balanced_mul(ctx, &cofactor_factors)
            };
            let cofactor_poly = Polynomial::from_expr(ctx, cofactor, var).ok()?;
            let domain_sample = explicit_sqrt_linear_domain_sample(ctx, den, var);
            let (arg, offset, _) = acosh_polynomial_substitution_oriented_arg(
                ctx,
                &cofactor_poly,
                radicand,
                var,
                domain_sample.as_ref(),
            )?;
            Some((radicand, arg, offset))
        }
        Expr::Mul(_, _) => {
            let domain_sample = explicit_sqrt_linear_domain_sample(ctx, expr, var);
            let factors = mul_leaves(ctx, expr);
            let (sqrt_index, radicand) = factors.iter().enumerate().find_map(|(idx, factor)| {
                reciprocal_sqrt_like_radicand(ctx, *factor).map(|radicand| (idx, radicand))
            })?;
            let (radicand, _) =
                split_positive_rational_content_from_sqrt_radicand(ctx, radicand, var)?;

            let cofactor_factors: Vec<ExprId> = factors
                .iter()
                .enumerate()
                .filter_map(|(idx, factor)| (idx != sqrt_index).then_some(*factor))
                .collect();
            let cofactor = if cofactor_factors.is_empty() {
                ctx.num(1)
            } else {
                build_balanced_mul(ctx, &cofactor_factors)
            };
            let cofactor_poly = Polynomial::from_expr(ctx, cofactor, var).ok()?;
            let (arg, offset, _) = acosh_polynomial_substitution_oriented_arg(
                ctx,
                &cofactor_poly,
                radicand,
                var,
                domain_sample.as_ref(),
            )?;
            Some((radicand, arg, offset))
        }
        _ => {
            let radicand = reciprocal_sqrt_like_radicand(ctx, expr)?;
            let (radicand, _) =
                split_positive_rational_content_from_sqrt_radicand(ctx, radicand, var)?;
            let one = ctx.num(1);
            let numerator = Polynomial::from_expr(ctx, one, var).ok()?;
            let (arg, offset, _) =
                acosh_polynomial_substitution_oriented_arg(ctx, &numerator, radicand, var, None)?;
            Some((radicand, arg, offset))
        }
    }
}

fn atanh_polynomial_substitution_denominator(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    let (num, den) = match ctx.get(expr).clone() {
        Expr::Div(num, den) => (num, den),
        _ => return None,
    };
    atanh_polynomial_substitution_antiderivative(ctx, num, den, var)?;
    Some(den)
}

fn atanh_polynomial_substitution_target_parts(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<()> {
    let (num, den) = match ctx.get(expr) {
        Expr::Div(num, den) => (*num, *den),
        _ => return None,
    };

    let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
    let denominator = Polynomial::from_expr(ctx, den, var).ok()?;
    let (arg_poly, offset_square) = exact_positive_constant_minus_polynomial_square(&denominator)?;
    let derivative = arg_poly.derivative();
    let scale = constant_polynomial_ratio(&numerator, &derivative)?;
    if scale.is_zero() || offset_square.is_zero() {
        return None;
    }

    Some(())
}

fn atanh_polynomial_substitution_arg_degree(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> Option<usize> {
    let (num, den) = match ctx.get(expr) {
        Expr::Div(num, den) => (*num, *den),
        _ => return None,
    };

    let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
    let denominator = Polynomial::from_expr(ctx, den, var).ok()?;
    let (arg_poly, offset_square) = exact_positive_constant_minus_polynomial_square(&denominator)?;
    let derivative = arg_poly.derivative();
    let scale = constant_polynomial_ratio(&numerator, &derivative)?;
    if scale.is_zero() || offset_square.is_zero() {
        return None;
    }

    Some(arg_poly.degree())
}

pub fn integrate_symbolic_is_atanh_polynomial_substitution_target(
    ctx: &Context,
    expr: ExprId,
    var: &str,
) -> bool {
    if let Some(inner) = constant_scaled_integrand_inner(ctx, expr, var) {
        return integrate_symbolic_is_atanh_polynomial_substitution_target(ctx, inner, var);
    }

    atanh_polynomial_substitution_target_parts(ctx, expr, var).is_some()
}

fn arctan_polynomial_substitution_arg_degree(
    ctx: &Context,
    num: ExprId,
    den: ExprId,
    var: &str,
) -> Option<usize> {
    let numerator = Polynomial::from_expr(ctx, num, var).ok()?;
    let denominator = Polynomial::from_expr(ctx, den, var).ok()?;
    let (arg_poly, offset_square) = exact_polynomial_square_plus_positive_constant(&denominator)?;
    if offset_square.is_zero() {
        return None;
    }

    let derivative = arg_poly.derivative();
    let scale = constant_polynomial_ratio(&numerator, &derivative)?;
    if scale.is_zero() {
        return None;
    }

    Some(arg_poly.degree())
}

fn inverse_sqrt_nested_polynomial_substitution_radicand(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Option<ExprId> {
    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            let radicand = sqrt_like_radicand(ctx, den)?;
            if arcsin_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
                || asinh_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
                || acosh_polynomial_substitution_div_antiderivative(ctx, num, den, var).is_some()
            {
                return Some(radicand);
            }
            None
        }
        Expr::Mul(_, _) => {
            let factors = mul_leaves(ctx, expr);
            let radicand = factors
                .iter()
                .find_map(|factor| reciprocal_sqrt_like_radicand(ctx, *factor))?;
            if arcsin_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some()
                || asinh_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some()
                || acosh_polynomial_substitution_product_antiderivative(ctx, expr, var).is_some()
            {
                return Some(radicand);
            }
            None
        }
        _ => None,
    }
}

pub fn integrate_symbolic_is_nested_inverse_polynomial_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    if let Some(inner) = constant_scaled_integrand_inner(ctx, expr, var) {
        return integrate_symbolic_is_nested_inverse_polynomial_substitution_target(
            ctx, inner, var,
        );
    }

    if let Some(radicand) = inverse_sqrt_nested_polynomial_substitution_radicand(ctx, expr, var) {
        return Polynomial::from_expr(ctx, radicand, var).is_ok_and(|poly| poly.degree() > 2);
    }

    let Expr::Div(num, den) = ctx.get(expr).clone() else {
        return false;
    };

    arctan_polynomial_substitution_arg_degree(ctx, num, den, var).is_some_and(|degree| degree > 1)
        || atanh_polynomial_substitution_arg_degree(ctx, expr, var).is_some_and(|degree| degree > 1)
}

pub fn integrate_symbolic_is_polynomial_base_substitution_target(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    if let Some(inner) = constant_scaled_integrand_inner(ctx, expr, var) {
        return integrate_symbolic_is_polynomial_base_substitution_target(ctx, inner, var);
    }

    match ctx.get(expr).clone() {
        Expr::Div(num, den) => {
            polynomial_log_derivative_antiderivative(ctx, num, den, var).is_some()
                || polynomial_log_derivative_power_antiderivative(ctx, num, den, var).is_some()
                || polynomial_log_reciprocal_derivative_antiderivative(ctx, num, den, var).is_some()
                || polynomial_denominator_power_substitution_antiderivative(ctx, num, den, var)
                    .is_some()
                || polynomial_negative_denominator_power_substitution_antiderivative(
                    ctx, num, den, var,
                )
                .is_some()
                || polynomial_reciprocal_quotient_denominator_power_substitution_antiderivative(
                    ctx, num, den, var,
                )
                .is_some()
                || sqrt_derivative_substitution_div_antiderivative(ctx, num, den, var).is_some()
        }
        _ => {
            polynomial_power_substitution_antiderivative(ctx, expr, var).is_some()
                || sqrt_derivative_substitution_product_antiderivative(ctx, expr, var).is_some()
                || sqrt_product_derivative_substitution_antiderivative(ctx, expr, var).is_some()
        }
    }
}

fn constant_scaled_integrand_inner(ctx: &Context, expr: ExprId, var: &str) -> Option<ExprId> {
    match ctx.get(expr) {
        Expr::Neg(inner) => Some(*inner),
        Expr::Mul(left, right) => {
            let left_depends_on_var = contains_named_var(ctx, *left, var);
            let right_depends_on_var = contains_named_var(ctx, *right, var);
            match (left_depends_on_var, right_depends_on_var) {
                (false, true) => Some(*right),
                (true, false) => Some(*left),
                _ => None,
            }
        }
        _ => None,
    }
}

type RequiredConditionFn = fn(&mut Context, ExprId, &str) -> Option<ExprId>;
type RequiredConditionsFn = fn(&mut Context, ExprId, &str) -> Vec<ExprId>;

enum RequiredConditionCollector {
    Optional(RequiredConditionFn),
    Multi(RequiredConditionsFn),
}

const REQUIRED_NONZERO_CONDITION_COLLECTORS_BEFORE_RESIDUAL_SCAN: &[RequiredConditionCollector] =
    &[RequiredConditionCollector::Optional(
        trig_log_required_nonzero,
    )];

const REQUIRED_NONZERO_CONDITION_COLLECTORS_AFTER_RESIDUAL_SCAN: &[RequiredConditionCollector] = &[
    RequiredConditionCollector::Optional(arctan_symbolic_scaled_variable_required_nonzero),
    RequiredConditionCollector::Optional(
        arctan_sqrt_var_symbolic_square_shift_required_nonzero_parameter,
    ),
    RequiredConditionCollector::Optional(polynomial_trig_log_required_nonzero),
    RequiredConditionCollector::Optional(reciprocal_trig_log_required_nonzero),
    RequiredConditionCollector::Optional(trig_log_derivative_ratio_required_nonzero),
    RequiredConditionCollector::Optional(trig_reciprocal_derivative_required_nonzero),
    RequiredConditionCollector::Optional(polynomial_trig_reciprocal_derivative_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_trig_reciprocal_derivative_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_trig_log_derivative_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_reciprocal_trig_log_derivative_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_hyperbolic_log_derivative_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_hyperbolic_reciprocal_square_required_nonzero),
    RequiredConditionCollector::Optional(sqrt_hyperbolic_reciprocal_derivative_required_nonzero),
    RequiredConditionCollector::Optional(polynomial_trig_reciprocal_factor_required_nonzero),
    RequiredConditionCollector::Optional(
        constant_scaled_trig_reciprocal_derivative_required_nonzero,
    ),
    RequiredConditionCollector::Optional(trig_ratio_power_reciprocal_square_required_nonzero),
    RequiredConditionCollector::Optional(polynomial_reciprocal_trig_square_required_nonzero),
    RequiredConditionCollector::Optional(polynomial_sec_csc_square_required_nonzero),
    RequiredConditionCollector::Optional(sec_fourth_required_nonzero),
    RequiredConditionCollector::Optional(csc_fourth_required_nonzero),
    RequiredConditionCollector::Optional(sec_sixth_required_nonzero),
    RequiredConditionCollector::Optional(csc_sixth_required_nonzero),
    RequiredConditionCollector::Optional(sec_eighth_required_nonzero),
    RequiredConditionCollector::Optional(csc_eighth_required_nonzero),
    RequiredConditionCollector::Optional(trig_ratio_square_required_nonzero),
    RequiredConditionCollector::Optional(reciprocal_trig_square_required_nonzero),
    RequiredConditionCollector::Optional(
        polynomial_denominator_power_substitution_required_nonzero,
    ),
    RequiredConditionCollector::Optional(
        polynomial_negative_denominator_power_substitution_required_nonzero,
    ),
    RequiredConditionCollector::Optional(
        polynomial_reciprocal_quotient_denominator_power_substitution_required_nonzero,
    ),
    RequiredConditionCollector::Multi(rational_linear_partial_fraction_required_nonzero),
    RequiredConditionCollector::Multi(rational_linear_positive_quadratic_required_nonzero),
];

fn collect_required_conditions_from(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
    collectors: &[RequiredConditionCollector],
    conditions: &mut Vec<ExprId>,
) {
    for collector in collectors {
        match collector {
            RequiredConditionCollector::Optional(collector) => {
                conditions.extend(collector(ctx, expr, var));
            }
            RequiredConditionCollector::Multi(collector) => {
                conditions.extend(collector(ctx, expr, var));
            }
        }
    }
}

pub fn integrate_symbolic_required_nonzero_conditions(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> Vec<ExprId> {
    if let Some(inner) = constant_scaled_integrand_inner(ctx, expr, var) {
        return integrate_symbolic_required_nonzero_conditions(ctx, inner, var);
    }

    let mut conditions = Vec::new();
    collect_required_conditions_from(
        ctx,
        expr,
        var,
        REQUIRED_NONZERO_CONDITION_COLLECTORS_BEFORE_RESIDUAL_SCAN,
        &mut conditions,
    );
    conditions.extend(residual_trig_pole_required_nonzero_conditions(ctx, expr));
    collect_required_conditions_from(
        ctx,
        expr,
        var,
        REQUIRED_NONZERO_CONDITION_COLLECTORS_AFTER_RESIDUAL_SCAN,
        &mut conditions,
    );

    dedup_required_conditions(ctx, conditions, var)
}

fn dedup_required_conditions(ctx: &mut Context, conditions: Vec<ExprId>, var: &str) -> Vec<ExprId> {
    let all_conditions = conditions.clone();
    let mut unique = Vec::new();
    for condition in conditions {
        if tanh_nonzero_dominated_by_sinh_nonzero(ctx, condition, &all_conditions) {
            continue;
        }
        if nonzero_condition_is_proven_for_symbolic_integration(ctx, condition) {
            continue;
        }
        if positive_constant_radius_quadratic_denominator_is_structurally_nonzero(
            ctx, condition, var,
        ) {
            continue;
        }
        if unique
            .iter()
            .any(|existing| compare_expr(ctx, *existing, condition) == Ordering::Equal)
        {
            continue;
        }
        unique.push(condition);
    }
    unique
}

fn nonzero_condition_is_proven_for_symbolic_integration(ctx: &mut Context, expr: ExprId) -> bool {
    if crate::calculus_domain_support::positive_condition_is_proven_over_reals(
        ctx,
        expr,
        SYMBOLIC_INTEGRATION_DOMAIN_PROOF_DEPTH,
    ) {
        return true;
    }

    match ctx.get(expr).clone() {
        Expr::Number(value) => !value.is_zero(),
        Expr::Constant(Constant::Pi | Constant::E | Constant::Phi) => true,
        Expr::Neg(inner) => nonzero_condition_is_proven_for_symbolic_integration(ctx, inner),
        Expr::Mul(_, _) => mul_leaves(ctx, expr)
            .into_iter()
            .all(|factor| nonzero_condition_is_proven_for_symbolic_integration(ctx, factor)),
        Expr::Div(num, den) => {
            nonzero_condition_is_proven_for_symbolic_integration(ctx, num)
                && nonzero_condition_is_proven_for_symbolic_integration(ctx, den)
        }
        Expr::Function(fn_id, args)
            if args.len() == 1 && ctx.builtin_of(fn_id) == Some(BuiltinFn::Sqrt) =>
        {
            crate::calculus_domain_support::positive_condition_is_proven_over_reals(
                ctx,
                args[0],
                SYMBOLIC_INTEGRATION_DOMAIN_PROOF_DEPTH,
            )
        }
        _ => false,
    }
}

fn positive_constant_radius_quadratic_denominator_is_structurally_nonzero(
    ctx: &mut Context,
    expr: ExprId,
    var: &str,
) -> bool {
    let parts = positive_square_constant_plus_square_arg(ctx, expr, var)
        .or_else(|| positive_square_constant_plus_expanded_square_arg(ctx, expr, var));
    let Some((arg, _radius)) = parts else {
        return false;
    };

    nonzero_linear_arg_and_slope(ctx, arg, var).is_some()
}

fn tanh_nonzero_dominated_by_sinh_nonzero(
    ctx: &Context,
    condition: ExprId,
    all_conditions: &[ExprId],
) -> bool {
    let Some(tanh_arg) = unary_builtin_arg(ctx, condition, BuiltinFn::Tanh) else {
        return false;
    };

    all_conditions.iter().any(|other| {
        let Some(sinh_arg) = unary_builtin_arg(ctx, *other, BuiltinFn::Sinh) else {
            return false;
        };
        compare_expr(ctx, sinh_arg, tanh_arg) == Ordering::Equal
    })
}

